#[derive(Clone, Debug, Eq, PartialEq)]
pub struct GpuWarnlistWarningDecisionCandidateReport {
    resource: String,
    loaded_warnlist: Option<GpuWarnlistReloadReport>,
    device_info: GpuWarnlistDeviceInfo,
    warnings: GpuWarnlistWarnings,
    blockers: Vec<String>,
}

impl GpuWarnlistWarningDecisionCandidateReport {
    fn loaded(
        resource: impl Into<String>,
        device_info: GpuWarnlistDeviceInfo,
        warnlist: &GpuWarnlist,
    ) -> Self {
        Self {
            resource: resource.into(),
            loaded_warnlist: Some(warnlist.report().clone()),
            warnings: warnlist.evaluate(&device_info),
            device_info,
            blockers: Vec::new(),
        }
    }

    fn blocked(
        resource: impl Into<String>,
        device_info: GpuWarnlistDeviceInfo,
        blocker: impl Into<String>,
    ) -> Self {
        Self {
            resource: resource.into(),
            loaded_warnlist: None,
            device_info,
            warnings: GpuWarnlistWarnings::default(),
            blockers: vec![blocker.into()],
        }
    }

    pub fn loaded_warnlist_report(&self) -> Option<&GpuWarnlistReloadReport> {
        self.loaded_warnlist.as_ref()
    }

    pub fn device_info(&self) -> &GpuWarnlistDeviceInfo {
        &self.device_info
    }

    pub fn warnings(&self) -> &GpuWarnlistWarnings {
        &self.warnings
    }

    pub fn blockers(&self) -> &[String] {
        &self.blockers
    }

    pub fn boundary_marker(&self) -> &'static str {
        GPU_WARNLIST_WARNING_DECISION_BOUNDARY
    }

    pub fn summary_fragment(&self) -> String {
        let warnlist = self
            .loaded_warnlist
            .as_ref()
            .map(|report| {
                format!(
                    "{}:{}",
                    report.loaded_resource_pack(),
                    report.pattern_counts_fragment()
                )
            })
            .unwrap_or_else(|| {
                format!(
                    "{}@<blocked>:renderer:0 version:0 vendor:0 patterns",
                    self.resource
                )
            });

        format!(
            "gpu_warnlist_decision_candidates:{warnlist} matches:{} blockers:{} {}",
            self.warnings.matched_warning_count(),
            self.blockers.len(),
            self.boundary_marker()
        )
    }

    pub fn items(&self) -> Vec<String> {
        let mut items = Vec::new();
        items.push(self.summary_fragment());
        items.push(self.gpu_facts_fragment());

        let categories = self.warnings.categories();
        if categories.is_empty() {
            items.push("gpu_warnlist_warnings:none".to_owned());
        } else {
            items.extend(
                categories.into_iter().map(|(category, matches)| {
                    format!("gpu_warnlist_warning:{category}:{matches}")
                }),
            );
        }

        if self.blockers.is_empty() {
            items.push("gpu_warnlist_blockers:0".to_owned());
        } else {
            items.extend(
                self.blockers
                    .iter()
                    .map(|blocker| format!("gpu_warnlist_blocker:{blocker}")),
            );
        }

        items.push(self.boundary_marker().to_owned());
        items
    }

    pub fn into_runtime_state(self) -> GpuWarnlistWarningState {
        GpuWarnlistWarningState::from(self)
    }

    fn gpu_facts_fragment(&self) -> String {
        let mut facts = vec![format!(
            "gpu_backend:{}",
            unavailable_if_empty(&self.device_info.backend)
        )];

        if !self.device_info.renderer.is_empty() {
            facts.push(format!("gpu_renderer:{}", self.device_info.renderer));
        }
        if !self.device_info.version.is_empty() {
            facts.push(format!("gpu_version:{}", self.device_info.version));
        }
        if !self.device_info.vendor.is_empty() {
            facts.push(format!("gpu_vendor:{}", self.device_info.vendor));
        }

        format!("gpu_warnlist_device:{}", facts.join(" "))
    }
}

#[derive(Clone, Debug, Eq, PartialEq)]
pub struct GpuWarnlistWarningState {
    report: GpuWarnlistWarningDecisionCandidateReport,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum GpuWarnlistWarningStateStatus {
    Loaded,
    Blocked,
}

impl GpuWarnlistWarningState {
    pub fn from_warnlist(device_info: GpuWarnlistDeviceInfo, warnlist: &GpuWarnlist) -> Self {
        GpuWarnlistWarningDecisionCandidateReport::loaded(
            warnlist.report().resource(),
            device_info,
            warnlist,
        )
        .into_runtime_state()
    }

    pub fn from_report(report: GpuWarnlistWarningDecisionCandidateReport) -> Self {
        Self { report }
    }

    pub fn status(&self) -> GpuWarnlistWarningStateStatus {
        if self.report.loaded_warnlist_report().is_some() && self.report.blockers().is_empty() {
            GpuWarnlistWarningStateStatus::Loaded
        } else {
            GpuWarnlistWarningStateStatus::Blocked
        }
    }

    pub fn is_loaded(&self) -> bool {
        self.status() == GpuWarnlistWarningStateStatus::Loaded
    }

    pub fn is_blocked(&self) -> bool {
        self.status() == GpuWarnlistWarningStateStatus::Blocked
    }

    pub fn device_info(&self) -> &GpuWarnlistDeviceInfo {
        self.report.device_info()
    }

    pub fn warnings(&self) -> &GpuWarnlistWarnings {
        self.report.warnings()
    }

    pub fn has_warnings(&self) -> bool {
        self.is_loaded() && !self.report.warnings().is_empty()
    }

    pub fn matched_category_count(&self) -> usize {
        self.report.warnings().categories().len()
    }

    pub fn matched_warning_count(&self) -> usize {
        self.report.warnings().matched_warning_count()
    }

    pub fn blockers(&self) -> &[String] {
        self.report.blockers()
    }

    pub fn loaded_warnlist_report(&self) -> Option<&GpuWarnlistReloadReport> {
        self.report.loaded_warnlist_report()
    }

    pub fn decision_candidate_report(&self) -> &GpuWarnlistWarningDecisionCandidateReport {
        &self.report
    }

    pub fn into_decision_candidate_report(self) -> GpuWarnlistWarningDecisionCandidateReport {
        self.report
    }
}

impl From<GpuWarnlistWarningDecisionCandidateReport> for GpuWarnlistWarningState {
    fn from(report: GpuWarnlistWarningDecisionCandidateReport) -> Self {
        Self { report }
    }
}

impl GpuWarnlistWarningDecisionCandidateReloadListener {
    pub fn new(resource: impl Into<String>) -> Self {
        Self {
            resource: resource.into(),
            device_info: GpuWarnlistDeviceInfo::default(),
        }
    }

    pub fn with_device_info(mut self, device_info: GpuWarnlistDeviceInfo) -> Self {
        self.device_info = device_info;
        self
    }

    pub fn report(&self, stack: &ClientResourceStack) -> GpuWarnlistWarningDecisionCandidateReport {
        match GpuWarnlistReloadListener::new(&self.resource).load(stack) {
            Ok(warnlist) => GpuWarnlistWarningDecisionCandidateReport::loaded(
                self.resource.clone(),
                self.device_info.clone(),
                &warnlist,
            ),
            Err(error) => GpuWarnlistWarningDecisionCandidateReport::blocked(
                self.resource.clone(),
                self.device_info.clone(),
                error.to_string(),
            ),
        }
    }

    pub fn state(&self, stack: &ClientResourceStack) -> GpuWarnlistWarningState {
        self.report(stack).into_runtime_state()
    }
}

impl Default for GpuWarnlistWarningDecisionCandidateReloadListener {
    fn default() -> Self {
        Self::new(GPU_WARNLIST_RESOURCE)
    }
}

impl ResourceReloadListener for GpuWarnlistWarningDecisionCandidateReloadListener {
    fn name(&self) -> &str {
        "gpu_warnlist_decision_candidates"
    }

    fn prepare(
        &self,
        _stack: &ClientResourceStack,
    ) -> ResourceReloadResult<ResourceReloadTaskReport> {
        Ok(ResourceReloadTaskReport::new([format!(
            "{}:{}",
            self.resource, GPU_WARNLIST_WARNING_DECISION_BOUNDARY
        )]))
    }

    fn reload(
        &self,
        stack: &ClientResourceStack,
    ) -> ResourceReloadResult<ResourceReloadTaskReport> {
        Ok(ResourceReloadTaskReport::new(self.report(stack).items()))
    }
}

fn unavailable_if_empty(value: &str) -> &str {
    if value.is_empty() {
        "unavailable"
    } else {
        value
    }
}

#[derive(Debug, Deserialize)]
struct GpuWarnlistDefinition {
    renderer: Vec<String>,
    version: Vec<String>,
    vendor: Vec<String>,
}

impl GpuWarnlistReloadListener {
    pub fn new(resource: impl Into<String>) -> Self {
        Self {
            resource: resource.into(),
        }
    }

    pub fn load(&self, stack: &ClientResourceStack) -> ResourceReloadResult<GpuWarnlist> {
        load_gpu_warnlist_resource(stack, &self.resource)
    }
}

impl Default for GpuWarnlistReloadListener {
    fn default() -> Self {
        Self::new(GPU_WARNLIST_RESOURCE)
    }
}

impl ResourceReloadListener for GpuWarnlistReloadListener {
    fn name(&self) -> &str {
        "gpu_warnlist"
    }

    fn prepare(
        &self,
        stack: &ClientResourceStack,
    ) -> ResourceReloadResult<ResourceReloadTaskReport> {
        stack.require_resource(&self.resource)?;
        Ok(ResourceReloadTaskReport::new([self.resource.clone()]))
    }

    fn reload(
        &self,
        stack: &ClientResourceStack,
    ) -> ResourceReloadResult<ResourceReloadTaskReport> {
        let warnlist = self.load(stack)?;
        Ok(ResourceReloadTaskReport::new([format!(
            "{}:{}",
            warnlist.report().loaded_resource_pack(),
            warnlist.report().pattern_counts_fragment()
        )]))
    }
}

fn load_gpu_warnlist_resource(
    stack: &ClientResourceStack,
    resource: impl AsRef<Path>,
) -> ResourceReloadResult<GpuWarnlist> {
    let resource = resource.as_ref();
    let json = load_client_json_resource(stack, resource)?;
    let definition: GpuWarnlistDefinition =
        serde_json::from_value(json.value().clone()).map_err(|source| {
            ResourceReloadError::InvalidGpuWarnlist {
                resource: json.report().resource().to_owned(),
                pack_id: json.report().pack_id().to_owned(),
                reason: source.to_string(),
            }
        })?;

    let renderer = compile_gpu_warnlist_patterns(
        json.report().resource(),
        json.report().pack_id(),
        "renderer",
        definition.renderer,
    )?;
    let version = compile_gpu_warnlist_patterns(
        json.report().resource(),
        json.report().pack_id(),
        "version",
        definition.version,
    )?;
    let vendor = compile_gpu_warnlist_patterns(
        json.report().resource(),
        json.report().pack_id(),
        "vendor",
        definition.vendor,
    )?;
    let report = GpuWarnlistReloadReport::new(
        json.report().resource(),
        json.report().pack_id(),
        renderer.len(),
        version.len(),
        vendor.len(),
    );

    Ok(GpuWarnlist {
        renderer,
        version,
        vendor,
        report,
    })
}

fn compile_gpu_warnlist_patterns(
    resource: &str,
    pack_id: &str,
    category: &str,
    patterns: Vec<String>,
) -> ResourceReloadResult<Vec<Regex>> {
    patterns
        .into_iter()
        .map(|pattern| {
            RegexBuilder::new(&pattern)
                .case_insensitive(true)
                .build()
                .map_err(|source| ResourceReloadError::InvalidGpuWarnlistRegex {
                    resource: resource.to_owned(),
                    pack_id: pack_id.to_owned(),
                    category: category.to_owned(),
                    pattern,
                    reason: source.to_string(),
                })
        })
        .collect()
}

fn collect_gpu_warnlist_matches(patterns: &[Regex], value: &str) -> Vec<String> {
    patterns
        .iter()
        .flat_map(|pattern| {
            pattern
                .find_iter(value)
                .map(|matched| matched.as_str().to_owned())
        })
        .collect()
}

#[derive(Clone, Debug, Eq, PartialEq)]
pub struct RegionalComplianciesReloadListener {
    resource: String,
}

impl RegionalComplianciesReloadListener {
    pub fn new(resource: impl Into<String>) -> Self {
        Self {
            resource: resource.into(),
        }
    }

    pub fn load(&self, stack: &ClientResourceStack) -> ResourceReloadResult<RegionalCompliancies> {
        load_regional_compliancies_resource(stack, &self.resource)
    }
}

impl Default for RegionalComplianciesReloadListener {
    fn default() -> Self {
        Self::new(REGIONAL_COMPLIANCIES_RESOURCE)
    }
}

impl ResourceReloadListener for RegionalComplianciesReloadListener {
    fn name(&self) -> &str {
        "regional_compliancies"
    }

    fn prepare(
        &self,
        stack: &ClientResourceStack,
    ) -> ResourceReloadResult<ResourceReloadTaskReport> {
        stack.require_resource(&self.resource)?;
        Ok(ResourceReloadTaskReport::new([self.resource.clone()]))
    }

    fn reload(
        &self,
        stack: &ClientResourceStack,
    ) -> ResourceReloadResult<ResourceReloadTaskReport> {
        let compliancies = self.load(stack)?;
        Ok(ResourceReloadTaskReport::new([format!(
            "{}:{}",
            compliancies.report().loaded_resource_pack(),
            compliancies.report().summary_fragment()
        )]))
    }
}

#[derive(Clone, Debug, Eq, PartialEq)]
pub struct RegionalComplianceNotificationDecisionCandidateReloadListener {
    resource: String,
    country_code: String,
}

#[derive(Clone, Debug, Eq, PartialEq)]
pub struct RegionalComplianceNotificationDecisionCandidateReport {
    resource: String,
    loaded_compliancies: Option<RegionalComplianciesReloadReport>,
    country_code: String,
    selected_notifications: Vec<RegionalComplianceNotification>,
    scheduling_plan: RegionalComplianceSchedulingPlan,
    blockers: Vec<String>,
}

impl RegionalComplianceNotificationDecisionCandidateReport {
    fn loaded(
        resource: impl Into<String>,
        country_code: String,
        compliancies: &RegionalCompliancies,
    ) -> Self {
        let selected_notifications = compliancies.select_notifications(&country_code).to_vec();
        let scheduling_plan = regional_compliance_scheduling_plan(&selected_notifications);

        Self {
            resource: resource.into(),
            loaded_compliancies: Some(compliancies.report().clone()),
            country_code,
            selected_notifications,
            scheduling_plan,
            blockers: Vec::new(),
        }
    }

    fn blocked(
        resource: impl Into<String>,
        country_code: String,
        blocker: impl Into<String>,
    ) -> Self {
        Self {
            resource: resource.into(),
            loaded_compliancies: None,
            country_code,
            selected_notifications: Vec::new(),
            scheduling_plan: RegionalComplianceSchedulingPlan::Disabled,
            blockers: vec![blocker.into()],
        }
    }

    pub fn loaded_compliancies_report(&self) -> Option<&RegionalComplianciesReloadReport> {
        self.loaded_compliancies.as_ref()
    }

    pub fn country_code(&self) -> &str {
        &self.country_code
    }

    pub fn selected_notifications(&self) -> &[RegionalComplianceNotification] {
        &self.selected_notifications
    }

    pub fn scheduling_plan(&self) -> RegionalComplianceSchedulingPlan {
        self.scheduling_plan
    }

    pub fn blockers(&self) -> &[String] {
        &self.blockers
    }

    pub fn boundary_marker(&self) -> &'static str {
        REGIONAL_COMPLIANCE_NOTIFICATION_DECISION_BOUNDARY
    }

    pub fn summary_fragment(&self) -> String {
        let loaded = self
            .loaded_compliancies
            .as_ref()
            .map(|report| {
                format!(
                    "{} status:{}",
                    report.loaded_resource_pack(),
                    report.status().report_fragment()
                )
            })
            .unwrap_or_else(|| format!("{}@<blocked> status:blocked", self.resource));

        format!(
            "regional_compliance_notification_decision_candidates:{loaded} country:{} selected:{} schedule:{} blockers:{} {}",
            self.country_code,
            self.selected_notifications.len(),
            self.scheduling_plan.kind_fragment(),
            self.blockers.len(),
            self.boundary_marker()
        )
    }

    pub fn items(&self) -> Vec<String> {
        let mut items = vec![self.summary_fragment()];

        if let Some(report) = &self.loaded_compliancies {
            items.push(format!(
                "regional_compliance_loaded:{} {}",
                report.loaded_resource_pack(),
                report.summary_fragment()
            ));
        } else {
            items.push(format!(
                "regional_compliance_loaded:{}@<blocked> status:blocked",
                self.resource
            ));
        }

        items.push(format!("regional_compliance_country:{}", self.country_code));
        items.push(format!(
            "regional_compliance_scheduling_plan:{}",
            self.scheduling_plan.report_fragment()
        ));

        if self.selected_notifications.is_empty() {
            items.push("regional_compliance_notifications:none".to_owned());
        } else {
            for (index, notification) in self.selected_notifications.iter().enumerate() {
                items.push(format!(
                    "regional_compliance_notification:{index} title:{} message:{} url:<not_parsed>",
                    notification.title(),
                    notification.message()
                ));
            }
        }

        if self.blockers.is_empty() {
            items.push("regional_compliance_blockers:0".to_owned());
        } else {
            items.extend(
                self.blockers
                    .iter()
                    .map(|blocker| format!("regional_compliance_blocker:{blocker}")),
            );
        }

        items.push(self.boundary_marker().to_owned());
        items
    }

    pub fn into_runtime_state(self) -> RegionalComplianceNotificationState {
        RegionalComplianceNotificationState::from(self)
    }
}

#[derive(Clone, Debug, Eq, PartialEq)]
pub struct RegionalComplianceNotificationState {
    report: RegionalComplianceNotificationDecisionCandidateReport,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum RegionalComplianceNotificationStateStatus {
    Loaded,
    Blocked,
}

impl RegionalComplianceNotificationState {
    pub fn from_compliancies(
        country_code: impl AsRef<str>,
        compliancies: &RegionalCompliancies,
    ) -> Self {
        RegionalComplianceNotificationDecisionCandidateReport::loaded(
            compliancies.report().resource(),
            normalize_regional_compliance_country_code(country_code.as_ref()),
            compliancies,
        )
        .into_runtime_state()
    }

    pub fn from_report(report: RegionalComplianceNotificationDecisionCandidateReport) -> Self {
        Self { report }
    }

    pub fn status(&self) -> RegionalComplianceNotificationStateStatus {
        if self.report.loaded_compliancies_report().is_some() && self.report.blockers().is_empty() {
            RegionalComplianceNotificationStateStatus::Loaded
        } else {
            RegionalComplianceNotificationStateStatus::Blocked
        }
    }

    pub fn is_loaded(&self) -> bool {
        self.status() == RegionalComplianceNotificationStateStatus::Loaded
    }

    pub fn is_blocked(&self) -> bool {
        self.status() == RegionalComplianceNotificationStateStatus::Blocked
    }

    pub fn country_code(&self) -> &str {
        self.report.country_code()
    }

    pub fn selected_notifications(&self) -> &[RegionalComplianceNotification] {
        self.report.selected_notifications()
    }

    pub fn scheduling_plan(&self) -> RegionalComplianceSchedulingPlan {
        self.report.scheduling_plan()
    }

    pub fn notifications_enabled(&self) -> bool {
        self.is_loaded() && self.scheduling_plan().is_enabled()
    }

    pub fn next_delay(&self) -> Option<i64> {
        self.scheduling_plan().initial_delay()
    }

    pub fn period(&self) -> Option<i64> {
        self.scheduling_plan().optimal_period()
    }

    pub fn blockers(&self) -> &[String] {
        self.report.blockers()
    }

    pub fn loaded_compliancies_report(&self) -> Option<&RegionalComplianciesReloadReport> {
        self.report.loaded_compliancies_report()
    }

    pub fn decision_candidate_report(
        &self,
    ) -> &RegionalComplianceNotificationDecisionCandidateReport {
        &self.report
    }

    pub fn into_decision_candidate_report(
        self,
    ) -> RegionalComplianceNotificationDecisionCandidateReport {
        self.report
    }
}

impl From<RegionalComplianceNotificationDecisionCandidateReport>
    for RegionalComplianceNotificationState
{
    fn from(report: RegionalComplianceNotificationDecisionCandidateReport) -> Self {
        Self { report }
    }
}

impl RegionalComplianceNotificationDecisionCandidateReloadListener {
    pub fn new(resource: impl Into<String>) -> Self {
        Self {
            resource: resource.into(),
            country_code: DEFAULT_REGIONAL_COMPLIANCE_COUNTRY_CODE.to_owned(),
        }
    }

    pub fn with_country_code(mut self, country_code: impl AsRef<str>) -> Self {
        self.country_code = normalize_regional_compliance_country_code(country_code.as_ref());
        self
    }

    pub fn report(
        &self,
        stack: &ClientResourceStack,
    ) -> RegionalComplianceNotificationDecisionCandidateReport {
        let country_code = normalize_regional_compliance_country_code(&self.country_code);
        match RegionalComplianciesReloadListener::new(&self.resource).load(stack) {
            Ok(compliancies) => RegionalComplianceNotificationDecisionCandidateReport::loaded(
                self.resource.clone(),
                country_code,
                &compliancies,
            ),
            Err(error) => RegionalComplianceNotificationDecisionCandidateReport::blocked(
                self.resource.clone(),
                country_code,
                error.to_string(),
            ),
        }
    }

    pub fn state(&self, stack: &ClientResourceStack) -> RegionalComplianceNotificationState {
        self.report(stack).into_runtime_state()
    }
}

impl Default for RegionalComplianceNotificationDecisionCandidateReloadListener {
    fn default() -> Self {
        Self::new(REGIONAL_COMPLIANCIES_RESOURCE)
    }
}

impl ResourceReloadListener for RegionalComplianceNotificationDecisionCandidateReloadListener {
    fn name(&self) -> &str {
        "regional_compliance_notification_decision_candidates"
    }

    fn prepare(
        &self,
        _stack: &ClientResourceStack,
    ) -> ResourceReloadResult<ResourceReloadTaskReport> {
        Ok(ResourceReloadTaskReport::new([format!(
            "{}:{}",
            self.resource, REGIONAL_COMPLIANCE_NOTIFICATION_DECISION_BOUNDARY
        )]))
    }

    fn reload(
        &self,
        stack: &ClientResourceStack,
    ) -> ResourceReloadResult<ResourceReloadTaskReport> {
        Ok(ResourceReloadTaskReport::new(self.report(stack).items()))
    }
}

#[derive(Clone, Debug, Eq, PartialEq)]
pub struct RegionalCompliancies {
    countries: BTreeMap<String, Vec<RegionalComplianceNotification>>,
    report: RegionalComplianciesReloadReport,
}

impl RegionalCompliancies {
    pub fn countries(&self) -> &BTreeMap<String, Vec<RegionalComplianceNotification>> {
        &self.countries
    }

    pub fn report(&self) -> &RegionalComplianciesReloadReport {
        &self.report
    }

    pub fn select_notifications(&self, iso3_country: &str) -> &[RegionalComplianceNotification] {
        let country = iso3_country.to_ascii_uppercase();
        self.countries
            .get(&country)
            .map(Vec::as_slice)
            .unwrap_or(&[])
    }

    pub fn scheduling_plan(&self, iso3_country: &str) -> RegionalComplianceSchedulingPlan {
        regional_compliance_scheduling_plan(self.select_notifications(iso3_country))
    }
}

