#[derive(Clone, Debug, Eq, PartialEq)]
pub struct ModelDependencyResourceReport {
    resource: String,
    pack_id: String,
    kind: ModelDependencyResourceKind,
}

impl ModelDependencyResourceReport {
    pub fn resource(&self) -> &str {
        &self.resource
    }

    pub fn pack_id(&self) -> &str {
        &self.pack_id
    }

    pub fn kind(&self) -> ModelDependencyResourceKind {
        self.kind
    }
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum ModelDependencyResourceKind {
    Blockstate,
    Model,
    BlockModel,
    ItemModel,
    ItemRoot,
}

impl ModelDependencyResourceKind {
    fn label(self) -> &'static str {
        match self {
            Self::Blockstate => "blockstates",
            Self::Model => "models",
            Self::BlockModel => "block_models",
            Self::ItemModel => "item_models",
            Self::ItemRoot => "item_roots",
        }
    }
}

#[derive(Clone, Copy, Debug, Default, Eq, PartialEq)]
pub struct ModelDependencyPackCounts {
    pub blockstates: usize,
    pub models: usize,
    pub block_models: usize,
    pub item_models: usize,
    pub item_roots: usize,
}

impl ModelDependencyPackCounts {
    fn increment(&mut self, kind: ModelDependencyResourceKind) {
        match kind {
            ModelDependencyResourceKind::Blockstate => self.blockstates += 1,
            ModelDependencyResourceKind::Model => self.models += 1,
            ModelDependencyResourceKind::BlockModel => self.block_models += 1,
            ModelDependencyResourceKind::ItemModel => self.item_models += 1,
            ModelDependencyResourceKind::ItemRoot => self.item_roots += 1,
        }
    }
}

pub fn load_model_dependencies(
    stack: &ClientResourceStack,
    blockstates: &[String],
    block_models: &[String],
    item_models: &[String],
    item_roots: &[String],
) -> ResourceReloadResult<ModelDependencyReport> {
    let mut discovered = DiscoveredModelDependencyResources::default();
    discovered.blockstates.extend(blockstates.iter().cloned());
    discovered.block_models.extend(block_models.iter().cloned());
    discovered.item_models.extend(item_models.iter().cloned());
    discovered.item_roots.extend(item_roots.iter().cloned());
    load_model_dependencies_from_resources(stack, &discovered)
}

fn load_discovered_model_dependencies(
    stack: &ClientResourceStack,
) -> ResourceReloadResult<ModelDependencyReport> {
    let resources = discover_model_dependency_resources(stack)?;
    load_model_dependencies_from_resources(stack, &resources)
}

fn load_model_dependencies_from_resources(
    stack: &ClientResourceStack,
    discovered: &DiscoveredModelDependencyResources,
) -> ResourceReloadResult<ModelDependencyReport> {
    let mut resources = Vec::new();
    let mut counts_by_top_priority_pack = BTreeMap::new();
    let mut blockstate_models = BTreeSet::new();
    let mut item_root_models = BTreeSet::new();
    let mut model_definitions = BTreeMap::new();
    let mut parents = BTreeSet::new();
    let mut textures = BTreeSet::new();

    for blockstate in &discovered.blockstates {
        let locations = stack.resource_stack(blockstate);
        if locations.is_empty() {
            return Err(ResourceReloadError::MissingResource(blockstate.clone()));
        }
        for location in locations {
            let resource = load_client_json_resource_at_location(blockstate, location)?;
            let model_references = extract_blockstate_model_references(resource.value())
                .map_err(|reason| invalid_model_dependency(&resource, reason))?;
            blockstate_models.extend(model_references);
            push_model_dependency_resource(
                &mut resources,
                &mut counts_by_top_priority_pack,
                resource.report(),
                ModelDependencyResourceKind::Blockstate,
            );
        }
    }

    for model in &discovered.models {
        let resource = load_client_json_resource(stack, model)?;
        let model_id = model_resource_id(model).ok_or_else(|| {
            invalid_model_dependency(&resource, format!("invalid model resource path `{model}`"))
        })?;
        let definition = parse_model_json_dependencies(&resource)?;
        collect_model_definition_dependencies(&definition, &mut parents, &mut textures);
        model_definitions.insert(model_id, definition);
        push_model_dependency_resource(
            &mut resources,
            &mut counts_by_top_priority_pack,
            resource.report(),
            ModelDependencyResourceKind::Model,
        );
    }

    for block_model in &discovered.block_models {
        let resource = load_client_json_resource(stack, block_model)?;
        let model_id = model_resource_id(block_model).ok_or_else(|| {
            invalid_model_dependency(
                &resource,
                format!("invalid model resource path `{block_model}`"),
            )
        })?;
        let definition = parse_model_json_dependencies(&resource)?;
        collect_model_definition_dependencies(&definition, &mut parents, &mut textures);
        model_definitions.insert(model_id, definition);
        push_model_dependency_resource(
            &mut resources,
            &mut counts_by_top_priority_pack,
            resource.report(),
            ModelDependencyResourceKind::BlockModel,
        );
    }

    for item_model in &discovered.item_models {
        let resource = load_client_json_resource(stack, item_model)?;
        let model_id = model_resource_id(item_model).ok_or_else(|| {
            invalid_model_dependency(
                &resource,
                format!("invalid model resource path `{item_model}`"),
            )
        })?;
        let definition = parse_model_json_dependencies(&resource)?;
        collect_model_definition_dependencies(&definition, &mut parents, &mut textures);
        model_definitions.insert(model_id, definition);
        push_model_dependency_resource(
            &mut resources,
            &mut counts_by_top_priority_pack,
            resource.report(),
            ModelDependencyResourceKind::ItemModel,
        );
    }

    for item_root in &discovered.item_roots {
        let resource = load_client_json_resource(stack, item_root)?;
        let model_references = extract_item_root_model_dependencies(resource.value())
            .map_err(|reason| invalid_model_dependency(&resource, reason))?;
        item_root_models.extend(model_references);
        push_model_dependency_resource(
            &mut resources,
            &mut counts_by_top_priority_pack,
            resource.report(),
            ModelDependencyResourceKind::ItemRoot,
        );
    }

    let mut root_models = BTreeSet::from(["minecraft:builtin/generated".to_owned()]);
    root_models.extend(blockstate_models.iter().cloned());
    root_models.extend(item_root_models.iter().cloned());
    let graph = resolve_model_dependency_graph(&model_definitions, &root_models);

    Ok(ModelDependencyReport {
        resources,
        counts_by_top_priority_pack,
        blockstate_models,
        item_root_models,
        root_models,
        reachable_models: graph.reachable_models,
        valid_models: graph.valid_models,
        missing_models: graph.missing_models,
        cyclic_models: graph.cyclic_models,
        unreferenced_model_count: graph.unreferenced_model_count,
        parents,
        textures,
    })
}

fn push_model_dependency_resource(
    resources: &mut Vec<ModelDependencyResourceReport>,
    counts_by_top_priority_pack: &mut BTreeMap<String, ModelDependencyPackCounts>,
    report: &ClientJsonResourceReloadReport,
    kind: ModelDependencyResourceKind,
) {
    counts_by_top_priority_pack
        .entry(report.pack_id().to_owned())
        .or_default()
        .increment(kind);
    resources.push(ModelDependencyResourceReport {
        resource: report.resource().to_owned(),
        pack_id: report.pack_id().to_owned(),
        kind,
    });
}

#[derive(Clone, Debug, Default, Eq, PartialEq)]
struct DiscoveredModelDependencyResources {
    blockstates: BTreeSet<String>,
    models: BTreeSet<String>,
    block_models: BTreeSet<String>,
    item_models: BTreeSet<String>,
    item_roots: BTreeSet<String>,
}

impl DiscoveredModelDependencyResources {
    fn all_resources(&self) -> Vec<String> {
        self.blockstates
            .iter()
            .chain(self.models.iter())
            .chain(self.block_models.iter())
            .chain(self.item_models.iter())
            .chain(self.item_roots.iter())
            .cloned()
            .collect()
    }
}

fn discover_model_dependency_resources(
    stack: &ClientResourceStack,
) -> ResourceReloadResult<DiscoveredModelDependencyResources> {
    let mut resources = DiscoveredModelDependencyResources::default();
    for pack in stack.packs() {
        match &pack.source {
            ClientResourcePackSource::Directory(root) => {
                discover_directory_model_dependency_resources(root, &mut resources)?
            }
            ClientResourcePackSource::RootZip(root) => {
                discover_zip_model_dependency_resources(root, &mut resources)?
            }
            ClientResourcePackSource::Unavailable(_) => {}
        }
    }
    Ok(resources)
}

fn discover_directory_model_dependency_resources(
    root: &Path,
    resources: &mut DiscoveredModelDependencyResources,
) -> ResourceReloadResult<()> {
    let assets = root.join("assets");
    if !assets.exists() {
        return Ok(());
    }
    discover_directory_model_dependency_resources_inner(root, &assets, resources)
}

fn discover_directory_model_dependency_resources_inner(
    root: &Path,
    directory: &Path,
    resources: &mut DiscoveredModelDependencyResources,
) -> ResourceReloadResult<()> {
    let entries = fs::read_dir(directory).map_err(|source| ResourceReloadError::ReadResource {
        resource: directory_resource_name(root, directory),
        path: directory.to_owned(),
        source,
    })?;

    for entry in entries {
        let entry = entry.map_err(|source| ResourceReloadError::ReadResource {
            resource: directory_resource_name(root, directory),
            path: directory.to_owned(),
            source,
        })?;
        let path = entry.path();
        if path.is_dir() {
            discover_directory_model_dependency_resources_inner(root, &path, resources)?;
            continue;
        }
        if !path.is_file() {
            continue;
        }
        let Ok(resource_path) = path.strip_prefix(root) else {
            continue;
        };
        if let Some(resource) = resource_path.to_str() {
            collect_model_dependency_resource_path(resource, resources);
        }
    }
    Ok(())
}

fn discover_zip_model_dependency_resources(
    root: &Path,
    resources: &mut DiscoveredModelDependencyResources,
) -> ResourceReloadResult<()> {
    let file = fs::File::open(root).map_err(|source| ResourceReloadError::ReadResource {
        resource: "assets/*/{models,blockstates,items}/**/*.json".to_owned(),
        path: root.to_owned(),
        source,
    })?;
    let mut archive =
        zip::ZipArchive::new(file).map_err(|source| ResourceReloadError::ReadResource {
            resource: "assets/*/{models,blockstates,items}/**/*.json".to_owned(),
            path: root.to_owned(),
            source: zip_error_to_io(source),
        })?;

    for index in 0..archive.len() {
        let entry =
            archive
                .by_index(index)
                .map_err(|source| ResourceReloadError::ReadResource {
                    resource: "assets/*/{models,blockstates,items}/**/*.json".to_owned(),
                    path: root.to_owned(),
                    source: zip_error_to_io(source),
                })?;
        if !entry.is_dir() {
            collect_model_dependency_resource_path(entry.name(), resources);
        }
    }
    Ok(())
}

fn collect_model_dependency_resource_path(
    resource: &str,
    resources: &mut DiscoveredModelDependencyResources,
) {
    let Some((_namespace, rest)) = resource.strip_prefix("assets/").and_then(|rest| {
        let (namespace, rest) = rest.split_once('/')?;
        Some((namespace, rest))
    }) else {
        return;
    };
    if !resource.ends_with(".json") {
        return;
    }
    if rest.starts_with("models/") {
        resources.models.insert(resource.to_owned());
    } else if rest.starts_with("blockstates/") {
        resources.blockstates.insert(resource.to_owned());
    } else if rest.starts_with("items/") {
        resources.item_roots.insert(resource.to_owned());
    }
}

#[derive(Clone, Debug, Default, Eq, PartialEq)]
struct ModelJsonDependencies {
    parent: Option<String>,
    textures: BTreeSet<String>,
    texture_slots: BTreeMap<String, String>,
    element_count: usize,
}

fn parse_model_json_dependencies(
    resource: &ClientJsonResource,
) -> ResourceReloadResult<ModelJsonDependencies> {
    let Some(object) = resource.value().as_object() else {
        return Err(invalid_model_dependency(
            resource,
            "model top-level value must be an object",
        ));
    };

    let mut dependencies = ModelJsonDependencies::default();
    if let Some(parent) = object.get("parent") {
        let Some(parent) = parent.as_str() else {
            return Err(invalid_model_dependency(
                resource,
                "model parent must be a string",
            ));
        };
        dependencies.parent = Some(normalize_model_id(parent));
    }

    if let Some(texture_values) = object.get("textures") {
        let Some(texture_values) = texture_values.as_object() else {
            return Err(invalid_model_dependency(
                resource,
                "model textures must be an object",
            ));
        };
        for (texture_key, texture) in texture_values {
            if let Some(texture) = texture.as_str() {
                dependencies.textures.insert(texture.to_owned());
                dependencies
                    .texture_slots
                    .insert(texture_key.clone(), texture.to_owned());
            } else if let Some(sprite) = texture
                .as_object()
                .and_then(|texture| texture.get("sprite"))
                .and_then(serde_json::Value::as_str)
            {
                dependencies.textures.insert(sprite.to_owned());
                dependencies
                    .texture_slots
                    .insert(texture_key.clone(), sprite.to_owned());
            } else {
                let _ = texture_key;
            }
        }
    }

    if let Some(elements) = object.get("elements") {
        let Some(elements) = elements.as_array() else {
            return Err(invalid_model_dependency(
                resource,
                "model elements must be an array",
            ));
        };
        dependencies.element_count = elements.len();
    }

    Ok(dependencies)
}

fn collect_model_definition_dependencies(
    dependencies: &ModelJsonDependencies,
    parents: &mut BTreeSet<String>,
    textures: &mut BTreeSet<String>,
) {
    if let Some(parent) = &dependencies.parent {
        parents.insert(parent.clone());
    }
    textures.extend(dependencies.textures.iter().cloned());
}

#[derive(Clone, Debug, Default, Eq, PartialEq)]
struct ModelDependencyGraphReport {
    reachable_models: BTreeSet<String>,
    valid_models: BTreeSet<String>,
    missing_models: BTreeSet<String>,
    cyclic_models: BTreeSet<String>,
    unreferenced_model_count: usize,
}

fn resolve_model_dependency_graph(
    definitions: &BTreeMap<String, ModelJsonDependencies>,
    roots: &BTreeSet<String>,
) -> ModelDependencyGraphReport {
    let mut graph = ModelDependencyGraphReport::default();
    let mut visiting = BTreeSet::new();
    let mut visited = BTreeSet::new();
    let mut stack = Vec::new();

    for root in roots {
        visit_model_dependency(
            root,
            definitions,
            &mut visiting,
            &mut visited,
            &mut stack,
            &mut graph,
        );
    }

    graph.valid_models = graph
        .reachable_models
        .difference(&graph.missing_models)
        .cloned()
        .collect();
    graph.unreferenced_model_count = definitions
        .keys()
        .filter(|model| !graph.reachable_models.contains(*model))
        .count();
    graph
}

fn visit_model_dependency(
    model: &str,
    definitions: &BTreeMap<String, ModelJsonDependencies>,
    visiting: &mut BTreeSet<String>,
    visited: &mut BTreeSet<String>,
    stack: &mut Vec<String>,
    graph: &mut ModelDependencyGraphReport,
) {
    graph.reachable_models.insert(model.to_owned());
    if visited.contains(model) {
        return;
    }
    if visiting.contains(model) {
        if let Some(position) = stack.iter().position(|stacked| stacked == model) {
            graph
                .cyclic_models
                .extend(stack[position..].iter().cloned());
        }
        graph.cyclic_models.insert(model.to_owned());
        return;
    }

    let Some(dependencies) = definitions.get(model) else {
        graph.missing_models.insert(model.to_owned());
        return;
    };

    visiting.insert(model.to_owned());
    stack.push(model.to_owned());
    if let Some(parent) = &dependencies.parent {
        visit_model_dependency(parent, definitions, visiting, visited, stack, graph);
    }
    stack.pop();
    visiting.remove(model);
    visited.insert(model.to_owned());
}

fn normalize_model_id(id: &str) -> String {
    if id.contains(':') {
        id.to_owned()
    } else {
        format!("minecraft:{id}")
    }
}

fn model_resource_id(resource: &str) -> Option<String> {
    resource_id_from_directory(resource, "models")
}

fn resource_id_from_directory(resource: &str, directory: &str) -> Option<String> {
    let rest = resource.strip_prefix("assets/")?;
    let (namespace, rest) = rest.split_once('/')?;
    let path = rest
        .strip_prefix(directory)?
        .strip_prefix('/')?
        .strip_suffix(".json")?;
    if namespace.is_empty() || path.is_empty() {
        return None;
    }
    Some(format!("{namespace}:{path}"))
}

pub fn extract_item_root_model_dependencies(
    item_root: &serde_json::Value,
) -> Result<BTreeSet<String>, String> {
    let Some(object) = item_root.as_object() else {
        return Err("item root top-level value must be an object".to_owned());
    };
    let Some(model) = object.get("model") else {
        return Err("item root must contain model".to_owned());
    };

    let mut model_references = BTreeSet::new();
    collect_item_model_dependencies(model, &mut model_references)?;
    Ok(model_references)
}

fn collect_item_model_dependencies(
    item_model: &serde_json::Value,
    model_references: &mut BTreeSet<String>,
) -> Result<(), String> {
    let Some(object) = item_model.as_object() else {
        return Err("item model must be an object".to_owned());
    };
    let Some(model_type) = object.get("type") else {
        return Err("item model must contain type".to_owned());
    };
    let Some(model_type) = model_type.as_str() else {
        return Err("item model type must be a string".to_owned());
    };

    match strip_minecraft_namespace(model_type) {
        "model" => {
            let Some(model) = object.get("model") else {
                return Err("minecraft:model item model must contain model".to_owned());
            };
            let Some(model) = model.as_str() else {
                return Err("minecraft:model item model model must be a string".to_owned());
            };
            model_references.insert(normalize_model_id(model));
        }
        "special" => {
            let Some(base) = object.get("base") else {
                return Err("minecraft:special item model must contain base".to_owned());
            };
            let Some(base) = base.as_str() else {
                return Err("minecraft:special item model base must be a string".to_owned());
            };
            model_references.insert(normalize_model_id(base));
        }
        "range_dispatch" => {
            if let Some(entries) = object.get("entries") {
                let Some(entries) = entries.as_array() else {
                    return Err("minecraft:range_dispatch entries must be an array".to_owned());
                };
                for entry in entries {
                    let Some(entry) = entry.as_object() else {
                        return Err("minecraft:range_dispatch entry must be an object".to_owned());
                    };
                    collect_required_child_item_model(
                        entry,
                        "model",
                        "minecraft:range_dispatch entry model",
                        model_references,
                    )?;
                }
            }
            collect_optional_child_item_model(
                object,
                "fallback",
                "minecraft:range_dispatch fallback",
                model_references,
            )?;
        }
        "select" => {
            if let Some(cases) = object.get("cases") {
                let Some(cases) = cases.as_array() else {
                    return Err("minecraft:select cases must be an array".to_owned());
                };
                for case in cases {
                    let Some(case) = case.as_object() else {
                        return Err("minecraft:select case must be an object".to_owned());
                    };
                    collect_required_child_item_model(
                        case,
                        "model",
                        "minecraft:select case model",
                        model_references,
                    )?;
                }
            }
            collect_optional_child_item_model(
                object,
                "fallback",
                "minecraft:select fallback",
                model_references,
            )?;
        }
        "condition" => {
            collect_required_child_item_model(
                object,
                "on_true",
                "minecraft:condition on_true",
                model_references,
            )?;
            collect_required_child_item_model(
                object,
                "on_false",
                "minecraft:condition on_false",
                model_references,
            )?;
        }
        "composite" => {
            let Some(models) = object.get("models") else {
                return Err("minecraft:composite item model must contain models".to_owned());
            };
            let Some(models) = models.as_array() else {
                return Err("minecraft:composite models must be an array".to_owned());
            };
            for model in models {
                collect_item_model_dependencies(model, model_references)?;
            }
        }
        "empty" | "bundle/selected_item" => {}
        _ => {
            return Err(format!("unsupported item model type `{model_type}`"));
        }
    }

    Ok(())
}

fn collect_required_child_item_model(
    object: &serde_json::Map<String, serde_json::Value>,
    field: &str,
    description: &str,
    model_references: &mut BTreeSet<String>,
) -> Result<(), String> {
    let Some(model) = object.get(field) else {
        return Err(format!("{description} must be present"));
    };
    collect_item_model_dependencies(model, model_references)
}

fn collect_optional_child_item_model(
    object: &serde_json::Map<String, serde_json::Value>,
    field: &str,
    description: &str,
    model_references: &mut BTreeSet<String>,
) -> Result<(), String> {
    if let Some(model) = object.get(field) {
        if !model.is_object() {
            return Err(format!("{description} must be an object"));
        }
        collect_item_model_dependencies(model, model_references)?;
    }
    Ok(())
}

fn strip_minecraft_namespace(model_type: &str) -> &str {
    model_type.strip_prefix("minecraft:").unwrap_or(model_type)
}

fn invalid_model_dependency(
    resource: &ClientJsonResource,
    reason: impl Into<String>,
) -> ResourceReloadError {
    ResourceReloadError::InvalidModelDependency {
        resource: resource.report().resource().to_owned(),
        pack_id: resource.report().pack_id().to_owned(),
        reason: reason.into(),
    }
}

fn model_dependency_report_items(report: &ModelDependencyReport) -> Vec<String> {
    let mut items = Vec::new();

    for resource in report.resources() {
        items.push(format!(
            "{}@{}:{}",
            resource.resource(),
            resource.pack_id(),
            resource.kind().label()
        ));
    }

    for (pack_id, counts) in report.counts_by_top_priority_pack() {
        items.push(format!(
            "pack:{pack_id}:blockstates:{} models:{} block_models:{} item_models:{} item_roots:{}",
            counts.blockstates,
            counts.models,
            counts.block_models,
            counts.item_models,
            counts.item_roots
        ));
    }

    let discovered_blockstates = report
        .resources()
        .iter()
        .filter(|resource| resource.kind() == ModelDependencyResourceKind::Blockstate)
        .map(|resource| resource.resource())
        .collect::<BTreeSet<_>>()
        .len();
    let discovered_models = report
        .resources()
        .iter()
        .filter(|resource| {
            matches!(
                resource.kind(),
                ModelDependencyResourceKind::Model
                    | ModelDependencyResourceKind::BlockModel
                    | ModelDependencyResourceKind::ItemModel
            )
        })
        .map(|resource| resource.resource())
        .collect::<BTreeSet<_>>()
        .len();
    let discovered_item_roots = report
        .resources()
        .iter()
        .filter(|resource| resource.kind() == ModelDependencyResourceKind::ItemRoot)
        .map(|resource| resource.resource())
        .collect::<BTreeSet<_>>()
        .len();

    items.push(format!(
        "discovered:blockstates:{discovered_blockstates} models:{discovered_models} item_roots:{discovered_item_roots} resources:{}",
        report.resources().len()
    ));
    items.push(format!(
        "roots:blockstates:{} items:{} total:{}",
        report.blockstate_models().len(),
        report.item_root_models().len(),
        report.root_models().len()
    ));
    items.push(format!(
        "resolved:reachable:{} valid:{} missing:{} cyclic:{} unreferenced:{}",
        report.reachable_models().len(),
        report.valid_models().len(),
        report.missing_models().len(),
        report.cyclic_models().len(),
        report.unreferenced_model_count()
    ));

    items.push(format!(
        "blockstate_models:{}",
        report
            .blockstate_models()
            .iter()
            .cloned()
            .collect::<Vec<_>>()
            .join(",")
    ));
    items.push(format!(
        "item_root_models:{}",
        report
            .item_root_models()
            .iter()
            .cloned()
            .collect::<Vec<_>>()
            .join(",")
    ));
    items.push(format!(
        "parents:{}",
        report
            .parents()
            .iter()
            .cloned()
            .collect::<Vec<_>>()
            .join(",")
    ));
    items.push(format!(
        "textures:{}",
        report
            .textures()
            .iter()
            .cloned()
            .collect::<Vec<_>>()
            .join(",")
    ));

    items
}

#[derive(Clone, Debug, Default, Eq, PartialEq)]
pub struct ModelBakeCandidateReloadListener;

impl ModelBakeCandidateReloadListener {
    pub fn load(
        &self,
        stack: &ClientResourceStack,
    ) -> ResourceReloadResult<ModelBakeCandidateReport> {
        load_model_bake_candidates(stack)
    }
}

impl ResourceReloadListener for ModelBakeCandidateReloadListener {
    fn name(&self) -> &str {
        "model_bake_candidates"
    }

    fn prepare(
        &self,
        stack: &ClientResourceStack,
    ) -> ResourceReloadResult<ResourceReloadTaskReport> {
        let resources = discover_model_dependency_resources(stack)?;
        Ok(ResourceReloadTaskReport::new(resources.all_resources()))
    }

    fn reload(
        &self,
        stack: &ClientResourceStack,
    ) -> ResourceReloadResult<ResourceReloadTaskReport> {
        let report = self.load(stack)?;
        Ok(ResourceReloadTaskReport::new(
            model_bake_candidate_report_items(&report),
        ))
    }
}

#[derive(Clone, Debug, Default, Eq, PartialEq)]
pub struct ItemModelResolverPropertyCandidateReloadListener;

impl ItemModelResolverPropertyCandidateReloadListener {
    pub fn load(
        &self,
        _stack: &ClientResourceStack,
    ) -> ResourceReloadResult<ItemModelResolverPropertyCandidateSet> {
        Ok(build_item_model_resolver_property_candidate_set())
    }
}

impl ResourceReloadListener for ItemModelResolverPropertyCandidateReloadListener {
    fn name(&self) -> &str {
        "item_model_resolver_property_candidates"
    }

    fn prepare(
        &self,
        stack: &ClientResourceStack,
    ) -> ResourceReloadResult<ResourceReloadTaskReport> {
        Ok(ResourceReloadTaskReport::new([self
            .load(stack)?
            .summary_fragment()]))
    }

    fn reload(
        &self,
        stack: &ClientResourceStack,
    ) -> ResourceReloadResult<ResourceReloadTaskReport> {
        Ok(ResourceReloadTaskReport::new(self.load(stack)?.items()))
    }
}

#[derive(Clone, Debug, Default, Eq, PartialEq)]
pub struct ModelManagerRuntimeCandidateReloadListener;

impl ModelManagerRuntimeCandidateReloadListener {
    pub fn load(
        &self,
        stack: &ClientResourceStack,
    ) -> ResourceReloadResult<ModelManagerRuntimeCandidateSet> {
        build_model_manager_runtime_candidate_set(stack)
    }

    pub fn load_state(
        &self,
        stack: &ClientResourceStack,
    ) -> ResourceReloadResult<ClientModelManagerState> {
        let bake = ModelBakeCandidateReloadListener.load(stack)?;
        let runtime = build_model_manager_runtime_candidate_set_from_bake(stack, &bake)?;
        Ok(ClientModelManagerState::from_reports(bake, runtime))
    }
}

impl ResourceReloadListener for ModelManagerRuntimeCandidateReloadListener {
    fn name(&self) -> &str {
        "model_manager_runtime_candidates"
    }

    fn prepare(
        &self,
        stack: &ClientResourceStack,
    ) -> ResourceReloadResult<ResourceReloadTaskReport> {
        let resources = discover_model_dependency_resources(stack)?;
        Ok(ResourceReloadTaskReport::new([
            format!("model_resources:{}", resources.all_resources().len()),
            format!("boundary:{MODEL_MANAGER_RUNTIME_BOUNDARY}"),
        ]))
    }

    fn reload(
        &self,
        stack: &ClientResourceStack,
    ) -> ResourceReloadResult<ResourceReloadTaskReport> {
        Ok(ResourceReloadTaskReport::new(self.load(stack)?.items()))
    }
}

#[derive(Clone, Debug, Eq, PartialEq)]
pub struct ModelBakeCandidateReport {
    dependency_report: ModelDependencyReport,
    blockstates: Vec<ModelBakeBlockstateCandidate>,
    item_roots: Vec<ModelBakeItemRootCandidate>,
    model_shapes: Vec<ModelBakeModelCandidate>,
    shape_counts: ModelBakeShapeCounts,
    root_item_model_type_counts: BTreeMap<String, usize>,
    item_model_type_counts: BTreeMap<String, usize>,
    texture_slots: BTreeMap<String, BTreeSet<String>>,
    valid_unbaked_models: BTreeSet<String>,
    missing_model_blockers: BTreeSet<String>,
    cyclic_model_blockers: BTreeSet<String>,
}

impl ModelBakeCandidateReport {
    pub fn dependency_report(&self) -> &ModelDependencyReport {
        &self.dependency_report
    }

    pub fn blockstates(&self) -> &[ModelBakeBlockstateCandidate] {
        &self.blockstates
    }

    pub fn item_roots(&self) -> &[ModelBakeItemRootCandidate] {
        &self.item_roots
    }

    pub fn model_shapes(&self) -> &[ModelBakeModelCandidate] {
        &self.model_shapes
    }

    pub fn shape_counts(&self) -> ModelBakeShapeCounts {
        self.shape_counts
    }

    pub fn root_item_model_type_counts(&self) -> &BTreeMap<String, usize> {
        &self.root_item_model_type_counts
    }

    pub fn item_model_type_counts(&self) -> &BTreeMap<String, usize> {
        &self.item_model_type_counts
    }

    pub fn texture_slots(&self) -> &BTreeMap<String, BTreeSet<String>> {
        &self.texture_slots
    }

    pub fn valid_unbaked_models(&self) -> &BTreeSet<String> {
        &self.valid_unbaked_models
    }

    pub fn missing_model_blockers(&self) -> &BTreeSet<String> {
        &self.missing_model_blockers
    }

    pub fn cyclic_model_blockers(&self) -> &BTreeSet<String> {
        &self.cyclic_model_blockers
    }

    pub fn blockstate_model_candidate_count(&self) -> usize {
        self.blockstates
            .iter()
            .map(ModelBakeBlockstateCandidate::model_candidate_count)
            .sum()
    }

    pub fn item_root_count(&self) -> usize {
        self.item_roots.len()
    }

    pub fn model_definition_count(&self) -> usize {
        self.model_shapes.len()
    }
}

