pub fn load_headless_shader_manager_prepare(
    stack: &ClientResourceStack,
) -> ResourceReloadResult<HeadlessShaderManagerPrepareReport> {
    let resources = discover_headless_shader_manager_resources(stack)?;
    let mut shader_sources = Vec::new();
    let mut includes = Vec::new();
    let mut post_chains = Vec::new();

    for resource in resources.shader_sources {
        shader_sources.push(load_headless_shader_source(stack, &resource)?);
    }
    for resource in resources.includes {
        includes.push(load_headless_shader_include(stack, &resource)?);
    }
    for resource in resources.post_chains {
        post_chains.push(load_headless_post_chain(stack, &resource)?);
    }

    Ok(HeadlessShaderManagerPrepareReport::new(
        shader_sources,
        includes,
        post_chains,
    ))
}

pub fn load_headless_shader_source(
    stack: &ClientResourceStack,
    resource: impl AsRef<Path>,
) -> ResourceReloadResult<HeadlessShaderSourceReloadReport> {
    let resource = resource.as_ref();
    let location = stack.require_resource(resource)?;
    let bytes = read_headless_shader_bytes(resource, &location)?;
    let resource_name = resource.to_string_lossy().into_owned();
    let source = validate_headless_shader_utf8(&resource_name, &location, &bytes)?;
    let id = shader_source_id(&resource_name)?;
    let extension = resource
        .extension()
        .and_then(|extension| extension.to_str())
        .unwrap_or_default();
    let kind = HeadlessShaderSourceKind::from_extension(extension).ok_or_else(|| {
        invalid_shader_source(
            &resource_name,
            &location,
            "shader source must end .vsh or .fsh",
        )
    })?;
    let imports = resolve_shader_imports(stack, &resource_name, &location, source)?;

    Ok(HeadlessShaderSourceReloadReport::new(
        id,
        kind,
        resource_name,
        location.pack_id,
        bytes.len(),
        imports,
    ))
}

fn load_headless_shader_include(
    stack: &ClientResourceStack,
    resource: impl AsRef<Path>,
) -> ResourceReloadResult<HeadlessShaderIncludeReport> {
    let resource = resource.as_ref();
    let location = stack.require_resource(resource)?;
    let bytes = read_headless_shader_bytes(resource, &location)?;
    let resource_name = resource.to_string_lossy().into_owned();
    validate_headless_shader_utf8(&resource_name, &location, &bytes)?;
    Ok(HeadlessShaderIncludeReport::new(
        resource_name,
        location.pack_id,
        bytes.len(),
    ))
}

fn read_headless_shader_bytes(
    resource: &Path,
    location: &ResourceLocation,
) -> ResourceReloadResult<Vec<u8>> {
    location
        .read_bytes()
        .map_err(|source| ResourceReloadError::ReadResource {
            resource: resource.to_string_lossy().into_owned(),
            path: location.path.clone(),
            source,
        })
}

fn validate_headless_shader_utf8<'a>(
    resource: &str,
    location: &ResourceLocation,
    bytes: &'a [u8],
) -> ResourceReloadResult<&'a str> {
    if bytes.is_empty() {
        return Err(ResourceReloadError::InvalidShaderSource {
            resource: resource.to_owned(),
            path: location.path.clone(),
            reason: "empty shader source".to_owned(),
        });
    }

    let source =
        std::str::from_utf8(bytes).map_err(|error| ResourceReloadError::InvalidShaderSource {
            resource: resource.to_owned(),
            path: location.path.clone(),
            reason: format!("shader source is not utf-8: {error}"),
        })?;

    if source.trim().is_empty() {
        return Err(ResourceReloadError::InvalidShaderSource {
            resource: resource.to_owned(),
            path: location.path.clone(),
            reason: "blank shader source".to_owned(),
        });
    }

    Ok(source)
}

fn invalid_shader_source(
    resource: &str,
    location: &ResourceLocation,
    reason: impl Into<String>,
) -> ResourceReloadError {
    ResourceReloadError::InvalidShaderSource {
        resource: resource.to_owned(),
        path: location.path.clone(),
        reason: reason.into(),
    }
}

#[derive(Clone, Debug, Default, Eq, PartialEq)]
struct HeadlessShaderManagerResources {
    shader_sources: Vec<String>,
    includes: Vec<String>,
    post_chains: Vec<String>,
}

fn discover_headless_shader_manager_resources(
    stack: &ClientResourceStack,
) -> ResourceReloadResult<HeadlessShaderManagerResources> {
    let mut resources = HeadlessShaderManagerResources::default();
    let mut shader_sources = BTreeSet::new();
    let mut includes = BTreeSet::new();
    let mut post_chains = BTreeSet::new();

    for pack in stack.packs() {
        match &pack.source {
            ClientResourcePackSource::Directory(root) => {
                discover_directory_shader_manager_resources(
                    root,
                    &mut shader_sources,
                    &mut includes,
                    &mut post_chains,
                )?
            }
            ClientResourcePackSource::RootZip(root) => discover_zip_shader_manager_resources(
                root,
                &mut shader_sources,
                &mut includes,
                &mut post_chains,
            )?,
            ClientResourcePackSource::Unavailable(_) => {}
        }
    }

    resources.shader_sources = shader_sources.into_iter().collect();
    resources.includes = includes.into_iter().collect();
    resources.post_chains = post_chains.into_iter().collect();
    Ok(resources)
}

fn discover_directory_shader_manager_resources(
    root: &Path,
    shader_sources: &mut BTreeSet<String>,
    includes: &mut BTreeSet<String>,
    post_chains: &mut BTreeSet<String>,
) -> ResourceReloadResult<()> {
    let assets = root.join("assets");
    if !assets.exists() {
        return Ok(());
    }

    discover_directory_shader_manager_resources_inner(
        root,
        &assets,
        shader_sources,
        includes,
        post_chains,
    )
}

fn discover_directory_shader_manager_resources_inner(
    root: &Path,
    directory: &Path,
    shader_sources: &mut BTreeSet<String>,
    includes: &mut BTreeSet<String>,
    post_chains: &mut BTreeSet<String>,
) -> ResourceReloadResult<()> {
    let entries = fs::read_dir(directory).map_err(|source| ResourceReloadError::ReadResource {
        resource: directory_resource_name(root, directory),
        path: directory.to_owned(),
        source,
    })?;

    for entry in entries {
        let entry = entry.map_err(|source| ResourceReloadError::ReadResource {
            resource: directory_resource_name(root, directory),
            path: directory.to_owned(),
            source,
        })?;
        let path = entry.path();
        if path.is_dir() {
            discover_directory_shader_manager_resources_inner(
                root,
                &path,
                shader_sources,
                includes,
                post_chains,
            )?;
            continue;
        }
        if !path.is_file() {
            continue;
        }
        let Ok(resource_path) = path.strip_prefix(root) else {
            continue;
        };
        if let Some(resource) = resource_path.to_str() {
            collect_shader_manager_resource_path(resource, shader_sources, includes, post_chains);
        }
    }

    Ok(())
}

fn discover_zip_shader_manager_resources(
    root: &Path,
    shader_sources: &mut BTreeSet<String>,
    includes: &mut BTreeSet<String>,
    post_chains: &mut BTreeSet<String>,
) -> ResourceReloadResult<()> {
    let file = fs::File::open(root).map_err(|source| ResourceReloadError::ReadResource {
        resource: "assets/*/{shaders,post_effect}".to_owned(),
        path: root.to_owned(),
        source,
    })?;
    let mut archive =
        zip::ZipArchive::new(file).map_err(|source| ResourceReloadError::ReadResource {
            resource: "assets/*/{shaders,post_effect}".to_owned(),
            path: root.to_owned(),
            source: zip_error_to_io(source),
        })?;

    for index in 0..archive.len() {
        let entry =
            archive
                .by_index(index)
                .map_err(|source| ResourceReloadError::ReadResource {
                    resource: "assets/*/{shaders,post_effect}".to_owned(),
                    path: root.to_owned(),
                    source: zip_error_to_io(source),
                })?;
        if entry.is_dir() {
            continue;
        }
        collect_shader_manager_resource_path(entry.name(), shader_sources, includes, post_chains);
    }

    Ok(())
}

fn collect_shader_manager_resource_path(
    resource: &str,
    shader_sources: &mut BTreeSet<String>,
    includes: &mut BTreeSet<String>,
    post_chains: &mut BTreeSet<String>,
) {
    let Some((namespace, rest)) = resource.strip_prefix("assets/").and_then(|rest| {
        let (namespace, rest) = rest.split_once('/')?;
        Some((namespace, rest))
    }) else {
        return;
    };

    if namespace.is_empty() || namespace.contains('/') {
        return;
    }

    if rest.starts_with("shaders/") {
        match Path::new(resource)
            .extension()
            .and_then(|extension| extension.to_str())
        {
            Some("vsh" | "fsh") => {
                shader_sources.insert(resource.to_owned());
            }
            Some("glsl") => {
                includes.insert(resource.to_owned());
            }
            _ => {}
        }
    } else if rest.starts_with("post_effect/")
        && !rest["post_effect/".len()..].contains('/')
        && resource.ends_with(".json")
    {
        post_chains.insert(resource.to_owned());
    }
}

fn directory_resource_name(root: &Path, directory: &Path) -> String {
    directory
        .strip_prefix(root)
        .unwrap_or(directory)
        .to_string_lossy()
        .into_owned()
}

fn shader_source_id(resource: &str) -> ResourceReloadResult<String> {
    let Some((namespace, rest)) = resource.strip_prefix("assets/").and_then(|rest| {
        let (namespace, rest) = rest.split_once("/shaders/")?;
        Some((namespace, rest))
    }) else {
        return Err(ResourceReloadError::MissingResource(resource.to_owned()));
    };
    let Some((path, _extension)) = rest.rsplit_once('.') else {
        return Err(ResourceReloadError::MissingResource(resource.to_owned()));
    };
    Ok(format!("{namespace}:{path}"))
}

fn resolve_shader_imports(
    stack: &ClientResourceStack,
    top_level_resource: &str,
    top_level_location: &ResourceLocation,
    source: &str,
) -> ResourceReloadResult<Vec<String>> {
    let mut imports = BTreeSet::new();
    for line in source.lines() {
        let Some(import) = parse_moj_import(line).map_err(|reason| {
            invalid_shader_source(top_level_resource, top_level_location, reason)
        })?
        else {
            continue;
        };
        let include =
            resolve_shader_import_resource(top_level_resource, &import).map_err(|reason| {
                invalid_shader_source(top_level_resource, top_level_location, reason)
            })?;
        let location = stack.require_resource(&include)?;
        let bytes = read_headless_shader_bytes(Path::new(&include), &location)?;
        validate_headless_shader_utf8(&include, &location, &bytes)?;
        imports.insert(include);
    }
    Ok(imports.into_iter().collect())
}

#[derive(Clone, Debug, Eq, PartialEq)]
enum MojImport {
    Relative(String),
    Id(String),
}

fn parse_moj_import(line: &str) -> Result<Option<MojImport>, String> {
    let line = line.trim_start();
    let Some(rest) = line.strip_prefix("#moj_import") else {
        return Ok(None);
    };
    let rest = rest.trim_start();
    if let Some(rest) = rest.strip_prefix('"') {
        let Some((path, _)) = rest.split_once('"') else {
            return Err("malformed #moj_import path".to_owned());
        };
        Ok(Some(MojImport::Relative(path.to_owned())))
    } else if let Some(rest) = rest.strip_prefix('<') {
        let Some((id, _)) = rest.split_once('>') else {
            return Err("malformed #moj_import id".to_owned());
        };
        Ok(Some(MojImport::Id(id.to_owned())))
    } else {
        Err("malformed #moj_import".to_owned())
    }
}

fn resolve_shader_import_resource(
    importing_resource: &str,
    import: &MojImport,
) -> Result<String, String> {
    match import {
        MojImport::Relative(path) => resolve_relative_shader_import(importing_resource, path),
        MojImport::Id(id) => resolve_id_shader_import(id),
    }
}

fn resolve_relative_shader_import(importing_resource: &str, path: &str) -> Result<String, String> {
    if path.is_empty() || path.starts_with('/') || path.contains('\\') {
        return Err(format!(
            "{importing_resource} imports malformed path `{path}`"
        ));
    }

    let mut parts = importing_resource
        .rsplit_once('/')
        .map(|(parent, _)| parent.split('/').collect::<Vec<_>>())
        .unwrap_or_default();
    for segment in path.split('/') {
        match segment {
            "" | "." => {}
            ".." => {
                if parts.pop().is_none() || parts.len() < 3 {
                    return Err(format!(
                        "{importing_resource} imports malformed path `{path}`"
                    ));
                }
            }
            segment => parts.push(segment),
        }
    }

    let resource = parts.join("/");
    if !resource.ends_with(".glsl") {
        return Err(format!(
            "{importing_resource} imports malformed path `{path}`"
        ));
    }
    Ok(resource)
}

fn resolve_id_shader_import(id: &str) -> Result<String, String> {
    let Some((namespace, path)) = id.split_once(':') else {
        return Err(format!("malformed shader import id `{id}`"));
    };
    if namespace.is_empty()
        || path.is_empty()
        || path.starts_with('/')
        || path.contains('\\')
        || path
            .split('/')
            .any(|segment| segment.is_empty() || segment == "." || segment == "..")
        || !path.ends_with(".glsl")
    {
        return Err(format!("malformed shader import id `{id}`"));
    }
    Ok(format!("assets/{namespace}/shaders/include/{path}"))
}

fn load_headless_post_chain(
    stack: &ClientResourceStack,
    resource: impl AsRef<Path>,
) -> ResourceReloadResult<HeadlessPostChainReport> {
    let resource = resource.as_ref();
    let location = stack.require_resource(resource)?;
    let json = read_client_json_resource(resource, &location)?;
    let value = json.value();
    let resource_name = resource.to_string_lossy().into_owned();
    let object = value.as_object().ok_or_else(|| {
        invalid_post_chain(
            &resource_name,
            &location,
            "post effect root must be an object",
        )
    })?;
    let target_count = object
        .get("targets")
        .and_then(serde_json::Value::as_object)
        .map(serde_json::Map::len)
        .unwrap_or(0);
    let passes = object
        .get("passes")
        .and_then(serde_json::Value::as_array)
        .ok_or_else(|| invalid_post_chain(&resource_name, &location, "missing passes array"))?;
    let mut shader_ids = BTreeSet::new();
    for (pass_index, pass) in passes.iter().enumerate() {
        let pass_object = pass.as_object().ok_or_else(|| {
            invalid_post_chain(
                &resource_name,
                &location,
                format!("pass {pass_index} must be an object"),
            )
        })?;
        for key in ["vertex_shader", "fragment_shader"] {
            let shader_id = pass_object
                .get(key)
                .and_then(serde_json::Value::as_str)
                .ok_or_else(|| {
                    invalid_post_chain(
                        &resource_name,
                        &location,
                        format!("pass {pass_index} missing {key} string"),
                    )
                })?;
            shader_ids.insert(shader_id.to_owned());
        }
        validate_post_pass_sampler_names(&resource_name, &location, pass_index, pass_object)?;
    }

    Ok(HeadlessPostChainReport::new(
        post_chain_id(&resource_name)?,
        resource_name,
        location.pack_id,
        target_count,
        passes.len(),
        shader_ids.into_iter().collect(),
    ))
}

fn validate_post_pass_sampler_names(
    resource: &str,
    location: &ResourceLocation,
    pass_index: usize,
    pass: &serde_json::Map<String, serde_json::Value>,
) -> ResourceReloadResult<()> {
    let Some(inputs) = pass.get("inputs") else {
        return Ok(());
    };
    let inputs = inputs.as_array().ok_or_else(|| {
        invalid_post_chain(
            resource,
            location,
            format!("pass {pass_index} inputs must be an array"),
        )
    })?;
    let mut sampler_names = BTreeSet::new();
    for (input_index, input) in inputs.iter().enumerate() {
        let sampler_name = input
            .as_object()
            .and_then(|input| input.get("sampler_name"))
            .and_then(serde_json::Value::as_str)
            .ok_or_else(|| {
                invalid_post_chain(
                    resource,
                    location,
                    format!("pass {pass_index} input {input_index} missing sampler_name string"),
                )
            })?;
        if !sampler_names.insert(sampler_name.to_owned()) {
            return Err(invalid_post_chain(
                resource,
                location,
                format!("pass {pass_index} has duplicate sampler `{sampler_name}`"),
            ));
        }
    }
    Ok(())
}

fn post_chain_id(resource: &str) -> ResourceReloadResult<String> {
    let Some((namespace, rest)) = resource.strip_prefix("assets/").and_then(|rest| {
        let (namespace, rest) = rest.split_once("/post_effect/")?;
        Some((namespace, rest))
    }) else {
        return Err(ResourceReloadError::MissingResource(resource.to_owned()));
    };
    let Some(id) = rest.strip_suffix(".json") else {
        return Err(ResourceReloadError::MissingResource(resource.to_owned()));
    };
    Ok(format!("{namespace}:{id}"))
}

fn invalid_post_chain(
    resource: &str,
    location: &ResourceLocation,
    reason: impl Into<String>,
) -> ResourceReloadError {
    ResourceReloadError::InvalidShaderSource {
        resource: resource.to_owned(),
        path: location.path.clone(),
        reason: reason.into(),
    }
}

pub fn load_headless_shader_manager_reload(
    stack: &ClientResourceStack,
    requested_post_chain_ids: &[String],
) -> ResourceReloadResult<HeadlessShaderManagerReloadReport> {
    let discovered = discover_headless_shader_manager_resources(stack)?;
    let post_chain_resources = selected_headless_post_chain_resources(
        stack,
        discovered.post_chains,
        requested_post_chain_ids,
    );
    let mut blockers = post_chain_resources.blockers;
    let mut shader_sources = BTreeMap::new();
    let mut shader_ids = BTreeSet::new();

    for resource in discovered.shader_sources {
        match load_headless_shader_source_inventory(stack, &resource) {
            Ok(source) => {
                shader_ids.insert(source.id.clone());
                blockers.extend(source.blockers.iter().cloned());
                shader_sources.insert((source.id.clone(), source.kind), source);
            }
            Err(blocker) => blockers.push(blocker),
        }
    }

    let mut program_candidates = Vec::new();
    for shader_id in shader_ids {
        let vertex = shader_sources.get(&(shader_id.clone(), HeadlessShaderSourceKind::Vertex));
        let fragment = shader_sources.get(&(shader_id.clone(), HeadlessShaderSourceKind::Fragment));
        if let (Some(vertex), Some(fragment)) = (vertex, fragment) {
            program_candidates.push(headless_shader_compile_candidate(
                format!("shader_pair:{shader_id}"),
                &shader_id,
                &shader_id,
                vertex,
                fragment,
            ));
        }
    }

    let mut post_chain_count = 0;
    for resource in post_chain_resources.resources {
        match load_headless_post_chain_compile_inputs(stack, &resource) {
            Ok(post_chain) => {
                post_chain_count += 1;
                for pass in post_chain.passes {
                    program_candidates.push(headless_post_chain_compile_candidate(
                        &post_chain.id,
                        &pass,
                        &shader_sources,
                    ));
                }
            }
            Err(blocker) => blockers.push(blocker),
        }
    }

    blockers.sort_by(|left, right| {
        left.resource
            .cmp(&right.resource)
            .then_with(|| left.reason.cmp(&right.reason))
    });
    blockers.dedup();

    Ok(HeadlessShaderManagerReloadReport::new(
        program_candidates,
        blockers,
        shader_sources.len(),
        post_chain_count,
    ))
}

pub fn load_shader_manager_runtime_candidates(
    stack: &ClientResourceStack,
    requested_post_chain_ids: &[String],
) -> ResourceReloadResult<ShaderManagerRuntimeCandidateReport> {
    let shader_manager = load_headless_shader_manager_reload(stack, requested_post_chain_ids)?;
    let manager_blockers = shader_manager
        .blockers()
        .iter()
        .map(|blocker| format!("{}:{}", blocker.resource(), blocker.reason()))
        .collect::<Vec<_>>();
    let program_candidate_count = shader_manager.program_candidates().len();
    let post_chain_count = shader_manager.post_chain_count();
    let ready_program_count = shader_manager.ready_candidate_count();
    let static_pipeline_dependency_count = ready_program_count.max(1);
    let post_chain_dependency_count = post_chain_count.max(requested_post_chain_ids.len());

    let mut candidates = vec![
        ShaderManagerRuntimeCandidate::new(
            "shader_manager:compilation_cache",
            ShaderManagerRuntimeCandidateCategory::CompilationCacheSwap,
            [
                "HeadlessShaderManagerReloadReport",
                "prepared_shader_sources",
                "prepared_post_chain_configs",
            ],
            program_candidate_count + post_chain_count,
            runtime_candidate_blockers(
                &manager_blockers,
                ["gpu_device_pipeline_cache_swap_not_implemented"],
            ),
        ),
        ShaderManagerRuntimeCandidate::new(
            "shader_manager:render_pipeline_precompile",
            ShaderManagerRuntimeCandidateCategory::RenderPipelinePrecompile,
            [
                "program_compile_candidates",
                "RenderPipelines::getStaticPipelines",
                "GpuDevice::precompilePipeline",
            ],
            static_pipeline_dependency_count,
            runtime_candidate_blockers(
                &manager_blockers,
                ["render_pipeline_precompile_backend_not_implemented"],
            ),
        ),
        ShaderManagerRuntimeCandidate::new(
            "shader_manager:post_chain_cache",
            ShaderManagerRuntimeCandidateCategory::PostChainLazyLoadCache,
            [
                "prepared_post_chain_configs",
                "CompilationCache::getOrLoadPostChain",
                "TextureManager",
            ],
            post_chain_dependency_count,
            runtime_candidate_blockers(
                &manager_blockers,
                ["post_chain_runtime_cache_not_implemented"],
            ),
        ),
        ShaderManagerRuntimeCandidate::new(
            "shader_manager:post_chain_projection_resources",
            ShaderManagerRuntimeCandidateCategory::ProjectionBufferResourcePool,
            [
                "PostChain::load",
                "Projection",
                "ProjectionMatrixBuffer",
                "GameRenderer::resourcePool",
            ],
            post_chain_dependency_count,
            ["projection_matrix_buffer_and_resource_pool_not_implemented"],
        ),
        ShaderManagerRuntimeCandidate::new(
            "shader_manager:ui_shader_preload_recovery",
            ShaderManagerRuntimeCandidateCategory::UiShaderPreloadRecoveryHandler,
            [
                "GameRenderer::preloadUiShader",
                "RenderPipelines::GUI",
                "RenderPipelines::GUI_TEXTURED",
                "ShaderManager::recoveryHandler",
            ],
            2,
            ["ui_shader_preload_and_recovery_handler_not_implemented"],
        ),
    ];

    candidates.sort_by(|left, right| {
        left.category()
            .as_str()
            .cmp(right.category().as_str())
            .then_with(|| left.id().cmp(right.id()))
    });

    Ok(ShaderManagerRuntimeCandidateReport::new(
        shader_manager,
        candidates,
    ))
}

fn runtime_candidate_blockers(
    manager_blockers: &[String],
    pending_blockers: impl IntoIterator<Item = impl Into<String>>,
) -> Vec<String> {
    let mut blockers = BTreeSet::new();
    blockers.extend(manager_blockers.iter().cloned());
    blockers.extend(pending_blockers.into_iter().map(Into::into));
    blockers.into_iter().collect()
}

#[derive(Clone, Debug, Default, Eq, PartialEq)]
struct SelectedHeadlessPostChainResources {
    resources: Vec<String>,
    blockers: Vec<HeadlessShaderManagerReloadBlocker>,
}

fn selected_headless_post_chain_resources(
    stack: &ClientResourceStack,
    discovered_post_chains: Vec<String>,
    requested_post_chain_ids: &[String],
) -> SelectedHeadlessPostChainResources {
    let mut resources = BTreeSet::from_iter(discovered_post_chains);
    let mut blockers = Vec::new();

    for id in requested_post_chain_ids {
        match post_chain_resource_from_id(id) {
            Ok(resource) => {
                if stack.find_resource(&resource).is_some() {
                    resources.insert(resource);
                } else {
                    blockers.push(HeadlessShaderManagerReloadBlocker::new(
                        resource,
                        format!("missing post-chain config `{id}`"),
                    ));
                }
            }
            Err(reason) => {
                blockers.push(HeadlessShaderManagerReloadBlocker::new(id.clone(), reason))
            }
        }
    }

    SelectedHeadlessPostChainResources {
        resources: resources.into_iter().collect(),
        blockers,
    }
}

fn post_chain_resource_from_id(id: &str) -> Result<String, String> {
    let Some((namespace, path)) = id.split_once(':') else {
        return Err(format!("malformed post-chain id `{id}`"));
    };
    if namespace.is_empty()
        || path.is_empty()
        || path.starts_with('/')
        || path.contains('\\')
        || path
            .split('/')
            .any(|segment| segment.is_empty() || segment == "." || segment == "..")
    {
        return Err(format!("malformed post-chain id `{id}`"));
    }
    Ok(format!("assets/{namespace}/post_effect/{path}.json"))
}

fn load_headless_shader_source_inventory(
    stack: &ClientResourceStack,
    resource: &str,
) -> Result<HeadlessShaderSourceInventory, HeadlessShaderManagerReloadBlocker> {
    let location = stack.find_resource(resource).ok_or_else(|| {
        HeadlessShaderManagerReloadBlocker::new(resource, "missing shader source")
    })?;
    let bytes = read_headless_shader_bytes(Path::new(resource), &location)
        .map_err(|error| shader_reload_blocker_from_error(resource, error))?;
    let source = validate_headless_shader_utf8(resource, &location, &bytes)
        .map_err(|error| shader_reload_blocker_from_error(resource, error))?;
    let id = shader_source_id(resource)
        .map_err(|error| shader_reload_blocker_from_error(resource, error))?;
    let extension = Path::new(resource)
        .extension()
        .and_then(|extension| extension.to_str())
        .unwrap_or_default();
    let kind = HeadlessShaderSourceKind::from_extension(extension).ok_or_else(|| {
        HeadlessShaderManagerReloadBlocker::new(resource, "shader source must end .vsh or .fsh")
    })?;
    let (imports, blockers) = resolve_shader_imports_for_reload(stack, resource, source);

    Ok(HeadlessShaderSourceInventory {
        id,
        kind,
        resource: resource.to_owned(),
        pack_id: location.pack_id,
        imports,
        blockers,
    })
}

fn shader_reload_blocker_from_error(
    resource: &str,
    error: ResourceReloadError,
) -> HeadlessShaderManagerReloadBlocker {
    match error {
        ResourceReloadError::MissingResource(missing) => {
            HeadlessShaderManagerReloadBlocker::new(missing, "missing resource")
        }
        ResourceReloadError::ReadResource { source, .. } => {
            HeadlessShaderManagerReloadBlocker::new(resource, format!("read failed: {source}"))
        }
        ResourceReloadError::ParseResourceJson { source, .. } => {
            HeadlessShaderManagerReloadBlocker::new(resource, format!("invalid json: {source}"))
        }
        ResourceReloadError::InvalidShaderSource { reason, .. } => {
            HeadlessShaderManagerReloadBlocker::new(resource, reason)
        }
        other => HeadlessShaderManagerReloadBlocker::new(resource, other.to_string()),
    }
}

fn resolve_shader_imports_for_reload(
    stack: &ClientResourceStack,
    top_level_resource: &str,
    source: &str,
) -> (Vec<String>, Vec<HeadlessShaderManagerReloadBlocker>) {
    let mut imports = BTreeSet::new();
    let mut imported_locations = BTreeSet::new();
    let mut blockers = Vec::new();
    collect_shader_imports_for_reload(
        stack,
        top_level_resource,
        top_level_resource,
        source,
        &mut imports,
        &mut imported_locations,
        &mut blockers,
    );
    (imports.into_iter().collect(), blockers)
}

fn collect_shader_imports_for_reload(
    stack: &ClientResourceStack,
    importing_resource: &str,
    top_level_resource: &str,
    source: &str,
    imports: &mut BTreeSet<String>,
    imported_locations: &mut BTreeSet<String>,
    blockers: &mut Vec<HeadlessShaderManagerReloadBlocker>,
) {
    for line in source.lines() {
        let import = match parse_moj_import(line) {
            Ok(Some(import)) => import,
            Ok(None) => continue,
            Err(reason) => {
                blockers.push(HeadlessShaderManagerReloadBlocker::new(
                    top_level_resource,
                    reason,
                ));
                continue;
            }
        };
        let include = match resolve_shader_import_resource(importing_resource, &import) {
            Ok(include) => include,
            Err(reason) => {
                blockers.push(HeadlessShaderManagerReloadBlocker::new(
                    top_level_resource,
                    reason,
                ));
                continue;
            }
        };
        if !imported_locations.insert(include.clone()) {
            continue;
        }
        imports.insert(include.clone());
        let Some(location) = stack.find_resource(&include) else {
            blockers.push(HeadlessShaderManagerReloadBlocker::new(
                include,
                "missing shader include",
            ));
            continue;
        };
        let bytes = match read_headless_shader_bytes(Path::new(&include), &location) {
            Ok(bytes) => bytes,
            Err(error) => {
                blockers.push(shader_reload_blocker_from_error(&include, error));
                continue;
            }
        };
        let include_source = match validate_headless_shader_utf8(&include, &location, &bytes) {
            Ok(source) => source,
            Err(error) => {
                blockers.push(shader_reload_blocker_from_error(&include, error));
                continue;
            }
        };
        collect_shader_imports_for_reload(
            stack,
            &include,
            top_level_resource,
            include_source,
            imports,
            imported_locations,
            blockers,
        );
    }
}

fn headless_shader_compile_candidate(
    id: impl Into<String>,
    vertex_shader_id: &str,
    fragment_shader_id: &str,
    vertex: &HeadlessShaderSourceInventory,
    fragment: &HeadlessShaderSourceInventory,
) -> HeadlessShaderProgramCompileCandidateReport {
    let mut imports = BTreeSet::new();
    imports.extend(vertex.imports.iter().cloned());
    imports.extend(fragment.imports.iter().cloned());
    let mut blockers = Vec::new();
    blockers.extend(vertex.blockers.iter().cloned());
    blockers.extend(fragment.blockers.iter().cloned());
    blockers.sort_by(|left, right| {
        left.resource
            .cmp(&right.resource)
            .then_with(|| left.reason.cmp(&right.reason))
    });
    blockers.dedup();

    HeadlessShaderProgramCompileCandidateReport::new(
        id,
        vertex_shader_id,
        fragment_shader_id,
        Some(vertex.loaded_resource_pack()),
        Some(fragment.loaded_resource_pack()),
        imports.into_iter().collect(),
        blockers,
    )
}

fn headless_post_chain_compile_candidate(
    post_chain_id: &str,
    pass: &HeadlessPostChainPassCompileInputs,
    shader_sources: &BTreeMap<(String, HeadlessShaderSourceKind), HeadlessShaderSourceInventory>,
) -> HeadlessShaderProgramCompileCandidateReport {
    let vertex_key = (
        pass.vertex_shader_id.clone(),
        HeadlessShaderSourceKind::Vertex,
    );
    let fragment_key = (
        pass.fragment_shader_id.clone(),
        HeadlessShaderSourceKind::Fragment,
    );
    let vertex = shader_sources.get(&vertex_key);
    let fragment = shader_sources.get(&fragment_key);
    match (vertex, fragment) {
        (Some(vertex), Some(fragment)) => headless_shader_compile_candidate(
            format!("post_chain:{post_chain_id}:pass:{}", pass.pass_index),
            &pass.vertex_shader_id,
            &pass.fragment_shader_id,
            vertex,
            fragment,
        ),
        _ => {
            let mut blockers = Vec::new();
            if vertex.is_none() {
                blockers.push(HeadlessShaderManagerReloadBlocker::new(
                    format!("shader:{}/vertex", pass.vertex_shader_id),
                    "missing shader source",
                ));
            }
            if fragment.is_none() {
                blockers.push(HeadlessShaderManagerReloadBlocker::new(
                    format!("shader:{}/fragment", pass.fragment_shader_id),
                    "missing shader source",
                ));
            }
            HeadlessShaderProgramCompileCandidateReport::new(
                format!("post_chain:{post_chain_id}:pass:{}", pass.pass_index),
                &pass.vertex_shader_id,
                &pass.fragment_shader_id,
                vertex.map(HeadlessShaderSourceInventory::loaded_resource_pack),
                fragment.map(HeadlessShaderSourceInventory::loaded_resource_pack),
                Vec::new(),
                blockers,
            )
        }
    }
}

fn load_headless_post_chain_compile_inputs(
    stack: &ClientResourceStack,
    resource: &str,
) -> Result<HeadlessPostChainCompileInputs, HeadlessShaderManagerReloadBlocker> {
    let location = stack.find_resource(resource).ok_or_else(|| {
        HeadlessShaderManagerReloadBlocker::new(resource, "missing post-chain config")
    })?;
    let json = read_client_json_resource(Path::new(resource), &location)
        .map_err(|error| shader_reload_blocker_from_error(resource, error))?;
    let value = json.value();
    let object = value.as_object().ok_or_else(|| {
        HeadlessShaderManagerReloadBlocker::new(resource, "post effect root must be an object")
    })?;
    let passes = match object.get("passes") {
        Some(passes) => passes.as_array().ok_or_else(|| {
            HeadlessShaderManagerReloadBlocker::new(resource, "passes must be an array")
        })?,
        None => {
            return Ok(HeadlessPostChainCompileInputs {
                id: post_chain_id(resource)
                    .map_err(|error| shader_reload_blocker_from_error(resource, error))?,
                passes: Vec::new(),
            });
        }
    };

    let mut pass_inputs = Vec::new();
    for (pass_index, pass) in passes.iter().enumerate() {
        let pass_object = pass.as_object().ok_or_else(|| {
            HeadlessShaderManagerReloadBlocker::new(
                resource,
                format!("pass {pass_index} must be an object"),
            )
        })?;
        let vertex_shader_id = pass_object
            .get("vertex_shader")
            .and_then(serde_json::Value::as_str)
            .ok_or_else(|| {
                HeadlessShaderManagerReloadBlocker::new(
                    resource,
                    format!("pass {pass_index} missing vertex_shader string"),
                )
            })?;
        let fragment_shader_id = pass_object
            .get("fragment_shader")
            .and_then(serde_json::Value::as_str)
            .ok_or_else(|| {
                HeadlessShaderManagerReloadBlocker::new(
                    resource,
                    format!("pass {pass_index} missing fragment_shader string"),
                )
            })?;
        pass_inputs.push(HeadlessPostChainPassCompileInputs {
            pass_index,
            vertex_shader_id: vertex_shader_id.to_owned(),
            fragment_shader_id: fragment_shader_id.to_owned(),
        });
    }

    Ok(HeadlessPostChainCompileInputs {
        id: post_chain_id(resource)
            .map_err(|error| shader_reload_blocker_from_error(resource, error))?,
        passes: pass_inputs,
    })
}

pub fn load_client_json_manifest_set(
    stack: &ClientResourceStack,
    directory: &str,
    ids: &[String],
) -> ResourceReloadResult<ClientJsonManifestSet> {
    let mut manifests = Vec::new();

    for id in ids {
        let resource = manifest_resource_path(directory, id);
        let Some(location) = stack.find_resource(&resource) else {
            continue;
        };
        let resource = read_client_json_resource(&resource, &location)?;
        manifests.push(ClientJsonManifest {
            id: id.clone(),
            resource,
        });
    }

    Ok(ClientJsonManifestSet { manifests })
}

pub fn load_client_json_manifest_directory(
    stack: &ClientResourceStack,
    directory: &str,
) -> ResourceReloadResult<ClientJsonManifestSet> {
    let ids = manifest_ids_in_directory(stack, directory)?;
    load_client_json_manifest_set(stack, directory, &ids)
}

pub fn load_client_particle_descriptions(
    stack: &ClientResourceStack,
    ids: &[String],
) -> ResourceReloadResult<ClientParticleDescriptionSet> {
    let manifests = if ids.is_empty() {
        load_client_json_manifest_directory(stack, PARTICLE_MANIFEST_DIR)?
    } else {
        load_client_json_manifest_set(stack, PARTICLE_MANIFEST_DIR, ids)?
    };
    let descriptions = manifests
        .manifests()
        .iter()
        .map(parse_client_particle_description)
        .collect::<ResourceReloadResult<Vec<_>>>()?;

    Ok(ClientParticleDescriptionSet { descriptions })
}

