#[derive(Clone, Debug, Eq, PartialEq)]
pub struct FontDefinitionsReloadListener {
    definitions: Vec<String>,
}

impl FontDefinitionsReloadListener {
    pub fn new(definitions: impl IntoIterator<Item = impl Into<String>>) -> Self {
        Self {
            definitions: definitions.into_iter().map(Into::into).collect(),
        }
    }

    pub fn definitions(&self) -> &[String] {
        &self.definitions
    }

    pub fn load(
        &self,
        stack: &ClientResourceStack,
    ) -> ResourceReloadResult<ClientFontDefinitionSet> {
        load_client_font_definitions(stack, &self.definitions)
    }
}

impl Default for FontDefinitionsReloadListener {
    fn default() -> Self {
        Self {
            definitions: Vec::new(),
        }
    }
}

impl ResourceReloadListener for FontDefinitionsReloadListener {
    fn name(&self) -> &str {
        "font_definitions"
    }

    fn prepare(
        &self,
        stack: &ClientResourceStack,
    ) -> ResourceReloadResult<ResourceReloadTaskReport> {
        Ok(ResourceReloadTaskReport::new(
            self.font_definition_resources(stack)?,
        ))
    }

    fn reload(
        &self,
        stack: &ClientResourceStack,
    ) -> ResourceReloadResult<ResourceReloadTaskReport> {
        let definitions = self.load(stack)?;
        Ok(ResourceReloadTaskReport::new(
            definitions.reports().map(font_definition_report_item),
        ))
    }
}

impl FontDefinitionsReloadListener {
    fn font_definition_resources(
        &self,
        stack: &ClientResourceStack,
    ) -> ResourceReloadResult<Vec<String>> {
        if self.definitions.is_empty() {
            discover_font_definition_resources(stack)
        } else {
            for definition in &self.definitions {
                stack.require_resource(definition)?;
            }
            Ok(self.definitions.clone())
        }
    }
}

pub fn load_client_font_definitions(
    stack: &ClientResourceStack,
    definitions: &[String],
) -> ResourceReloadResult<ClientFontDefinitionSet> {
    let definitions = if definitions.is_empty() {
        discover_font_definition_resources(stack)?
    } else {
        definitions.to_vec()
    };
    let mut loaded = Vec::new();

    for definition in &definitions {
        let locations = stack.resource_stack(definition);
        if locations.is_empty() {
            return Err(ResourceReloadError::MissingResource(definition.clone()));
        }

        for location in locations {
            let resource = read_client_json_resource(Path::new(definition), &location)?;
            let providers = parse_font_definition_providers(&resource)?;
            loaded.push(ClientFontDefinition {
                resource,
                providers,
            });
        }
    }

    Ok(ClientFontDefinitionSet {
        definitions: loaded,
    })
}

fn discover_font_definition_resources(
    stack: &ClientResourceStack,
) -> ResourceReloadResult<Vec<String>> {
    let mut resources = BTreeSet::new();

    for pack in stack.packs() {
        match &pack.source {
            ClientResourcePackSource::Directory(root) => {
                discover_directory_font_definition_resources(root, &mut resources)?
            }
            ClientResourcePackSource::RootZip(root) => {
                discover_zip_font_definition_resources(root, &mut resources)?
            }
            ClientResourcePackSource::Unavailable(_) => {}
        }
    }

    if resources.is_empty() {
        return Err(ResourceReloadError::MissingResource(
            FONT_DEFINITION_RESOURCE_GLOB.to_owned(),
        ));
    }

    Ok(resources.into_iter().collect())
}

fn discover_directory_font_definition_resources(
    root: &Path,
    resources: &mut BTreeSet<String>,
) -> ResourceReloadResult<()> {
    let assets = root.join("assets");
    if !assets.exists() {
        return Ok(());
    }

    let namespaces = fs::read_dir(&assets).map_err(|source| ResourceReloadError::ReadResource {
        resource: "assets".to_owned(),
        path: assets.clone(),
        source,
    })?;
    for namespace in namespaces {
        let namespace = namespace.map_err(|source| ResourceReloadError::ReadResource {
            resource: "assets".to_owned(),
            path: assets.clone(),
            source,
        })?;
        let namespace_path = namespace.path();
        if !namespace_path.is_dir() {
            continue;
        }
        let fonts = namespace_path.join("font");
        if fonts.exists() {
            discover_directory_font_definition_resources_inner(root, &fonts, resources)?;
        }
    }

    Ok(())
}

fn discover_directory_font_definition_resources_inner(
    root: &Path,
    directory: &Path,
    resources: &mut BTreeSet<String>,
) -> ResourceReloadResult<()> {
    let entries = fs::read_dir(directory).map_err(|source| ResourceReloadError::ReadResource {
        resource: directory_resource_name(root, directory),
        path: directory.to_owned(),
        source,
    })?;

    for entry in entries {
        let entry = entry.map_err(|source| ResourceReloadError::ReadResource {
            resource: directory_resource_name(root, directory),
            path: directory.to_owned(),
            source,
        })?;
        let path = entry.path();
        if path.is_dir() {
            discover_directory_font_definition_resources_inner(root, &path, resources)?;
            continue;
        }
        if !path.is_file() {
            continue;
        }

        let Ok(relative) = path.strip_prefix(root) else {
            continue;
        };
        if let Some(resource) = relative.to_str() {
            collect_font_definition_resource_path(resource, resources);
        }
    }

    Ok(())
}

fn discover_zip_font_definition_resources(
    root: &Path,
    resources: &mut BTreeSet<String>,
) -> ResourceReloadResult<()> {
    let file = fs::File::open(root).map_err(|source| ResourceReloadError::ReadResource {
        resource: FONT_DEFINITION_RESOURCE_GLOB.to_owned(),
        path: root.to_owned(),
        source,
    })?;
    let mut archive =
        zip::ZipArchive::new(file).map_err(|source| ResourceReloadError::ReadResource {
            resource: FONT_DEFINITION_RESOURCE_GLOB.to_owned(),
            path: root.to_owned(),
            source: zip_error_to_io(source),
        })?;

    for index in 0..archive.len() {
        let entry =
            archive
                .by_index(index)
                .map_err(|source| ResourceReloadError::ReadResource {
                    resource: FONT_DEFINITION_RESOURCE_GLOB.to_owned(),
                    path: root.to_owned(),
                    source: zip_error_to_io(source),
                })?;
        if !entry.is_dir() {
            collect_font_definition_resource_path(entry.name(), resources);
        }
    }
    Ok(())
}

fn collect_font_definition_resource_path(resource: &str, resources: &mut BTreeSet<String>) {
    let Some((_namespace, rest)) = resource.strip_prefix("assets/").and_then(|rest| {
        let (namespace, rest) = rest.split_once('/')?;
        Some((namespace, rest))
    }) else {
        return;
    };
    if rest.starts_with("font/") && resource.ends_with(".json") {
        resources.insert(resource.to_owned());
    }
}

fn parse_font_definition_providers(
    resource: &ClientJsonResource,
) -> ResourceReloadResult<Vec<ClientFontProviderDefinition>> {
    let providers = resource
        .value()
        .get("providers")
        .and_then(serde_json::Value::as_array)
        .ok_or_else(|| invalid_font_definition(resource, "missing providers array"))?;

    if let Some(index) = providers.iter().position(|provider| !provider.is_object()) {
        return Err(invalid_font_definition(
            resource,
            format!("provider {index} is not an object"),
        ));
    }

    let definition: RawClientFontDefinition = serde_json::from_value(resource.value().clone())
        .map_err(|source| {
            invalid_font_definition(resource, format!("invalid provider definition: {source}"))
        })?;

    definition
        .providers
        .into_iter()
        .enumerate()
        .map(|(index, provider)| {
            validate_font_provider_definition(resource, index, &provider)?;
            let referenced_assets = font_provider_referenced_assets(resource, index, &provider)?;
            let asset_candidates = font_provider_asset_candidates(resource, index, &provider)?;
            let referenced_provider_ids =
                font_provider_referenced_provider_ids(resource, index, &provider)?;
            let glyph_source_estimate =
                font_provider_glyph_source_estimate(resource, index, &provider)?;
            Ok(ClientFontProviderDefinition {
                provider_index: index,
                provider_type: provider.provider_type,
                referenced_assets,
                asset_candidates,
                referenced_provider_ids,
                glyph_source_estimate,
            })
        })
        .collect()
}

fn validate_font_provider_definition(
    resource: &ClientJsonResource,
    index: usize,
    provider: &RawClientFontProviderDefinition,
) -> ResourceReloadResult<()> {
    validate_font_provider_filter(resource, index, provider)?;

    match provider.provider_type.as_str() {
        "reference" => {
            require_font_provider_identifier_field(resource, index, provider, "id").map(|_| ())
        }
        "bitmap" => {
            require_font_provider_identifier_field(resource, index, provider, "file")?;
            require_font_provider_i64_field(resource, index, provider, "ascent")?;
            if let Some(height) = provider.fields.get("height") {
                if !height.is_i64() {
                    return Err(invalid_font_definition(
                        resource,
                        format!("provider {index} `height` must be an integer"),
                    ));
                }
            }
            validate_bitmap_font_provider_height(resource, index, provider)?;
            validate_bitmap_font_provider_chars(resource, index, provider)
        }
        "space" => require_font_provider_object_field(resource, index, provider, "advances")
            .and_then(|advances| {
                if advances.values().all(serde_json::Value::is_number) {
                    Ok(())
                } else {
                    Err(invalid_font_definition(
                        resource,
                        format!("provider {index} space advances must be numbers"),
                    ))
                }
            }),
        "ttf" => {
            require_font_provider_identifier_field(resource, index, provider, "file")?;
            if let Some(size) = provider.fields.get("size") {
                if !size.is_number() {
                    return Err(invalid_font_definition(
                        resource,
                        format!("provider {index} ttf size must be a number"),
                    ));
                }
            }
            if let Some(oversample) = provider.fields.get("oversample") {
                if !oversample.is_number() {
                    return Err(invalid_font_definition(
                        resource,
                        format!("provider {index} ttf oversample must be a number"),
                    ));
                }
            }
            validate_font_provider_shift(resource, index, provider)?;
            validate_font_provider_skip(resource, index, provider)?;
            Ok(())
        }
        "unihex" => {
            require_font_provider_identifier_field(resource, index, provider, "hex_file")?;
            validate_unihex_size_overrides(resource, index, provider)
        }
        other => Err(invalid_font_definition(
            resource,
            format!("provider {index} has unsupported type `{other}`"),
        )),
    }
}

fn validate_font_provider_filter(
    resource: &ClientJsonResource,
    index: usize,
    provider: &RawClientFontProviderDefinition,
) -> ResourceReloadResult<()> {
    let Some(filter) = provider.fields.get("filter") else {
        return Ok(());
    };
    let Some(filter) = filter.as_object() else {
        return Err(invalid_font_definition(
            resource,
            format!("provider {index} filter must be an object"),
        ));
    };
    for (key, value) in filter {
        if !matches!(key.as_str(), "uniform" | "jp") {
            return Err(invalid_font_definition(
                resource,
                format!("provider {index} filter has unsupported option `{key}`"),
            ));
        }
        if !value.is_boolean() {
            return Err(invalid_font_definition(
                resource,
                format!("provider {index} filter `{key}` must be a boolean"),
            ));
        }
    }
    Ok(())
}

fn validate_bitmap_font_provider_height(
    resource: &ClientJsonResource,
    index: usize,
    provider: &RawClientFontProviderDefinition,
) -> ResourceReloadResult<()> {
    let ascent = require_font_provider_i64_field(resource, index, provider, "ascent")?;
    let height = provider
        .fields
        .get("height")
        .and_then(serde_json::Value::as_i64)
        .unwrap_or(8);
    if ascent > height {
        return Err(invalid_font_definition(
            resource,
            format!("provider {index} bitmap ascent must not exceed height"),
        ));
    }
    Ok(())
}

fn validate_bitmap_font_provider_chars(
    resource: &ClientJsonResource,
    index: usize,
    provider: &RawClientFontProviderDefinition,
) -> ResourceReloadResult<()> {
    let Some(chars) = provider
        .fields
        .get("chars")
        .and_then(serde_json::Value::as_array)
    else {
        return Err(invalid_font_definition(
            resource,
            format!("provider {index} bitmap chars must be an array"),
        ));
    };
    if chars.is_empty() {
        return Err(invalid_font_definition(
            resource,
            format!("provider {index} bitmap chars must not be empty"),
        ));
    }

    let mut row_width = None;
    for row in chars {
        let Some(row) = row.as_str() else {
            return Err(invalid_font_definition(
                resource,
                format!("provider {index} bitmap chars rows must be strings"),
            ));
        };
        let width = row.chars().count();
        if width == 0 {
            return Err(invalid_font_definition(
                resource,
                format!("provider {index} bitmap chars rows must not be empty"),
            ));
        }
        match row_width {
            Some(expected) if expected != width => {
                return Err(invalid_font_definition(
                    resource,
                    format!("provider {index} bitmap chars rows must have equal width"),
                ));
            }
            Some(_) => {}
            None => row_width = Some(width),
        }
    }

    Ok(())
}

fn validate_font_provider_shift(
    resource: &ClientJsonResource,
    index: usize,
    provider: &RawClientFontProviderDefinition,
) -> ResourceReloadResult<()> {
    let Some(shift) = provider.fields.get("shift") else {
        return Ok(());
    };
    let Some(shift) = shift.as_array() else {
        return Err(invalid_font_definition(
            resource,
            format!("provider {index} ttf shift must be an array"),
        ));
    };
    if shift.len() != 2 || !shift.iter().all(serde_json::Value::is_number) {
        return Err(invalid_font_definition(
            resource,
            format!("provider {index} ttf shift must contain 2 numbers"),
        ));
    }
    if shift.iter().any(|value| {
        value
            .as_f64()
            .is_some_and(|number| !(-512.0..=512.0).contains(&number))
    }) {
        return Err(invalid_font_definition(
            resource,
            format!("provider {index} ttf shift values must be between -512 and 512"),
        ));
    }
    Ok(())
}

fn validate_font_provider_skip(
    resource: &ClientJsonResource,
    index: usize,
    provider: &RawClientFontProviderDefinition,
) -> ResourceReloadResult<()> {
    let Some(skip) = provider.fields.get("skip") else {
        return Ok(());
    };
    if skip.is_string() {
        return Ok(());
    }
    if skip
        .as_array()
        .is_some_and(|items| items.iter().all(serde_json::Value::is_string))
    {
        return Ok(());
    }
    Err(invalid_font_definition(
        resource,
        format!("provider {index} ttf skip must be a string or string array"),
    ))
}

fn validate_unihex_size_overrides(
    resource: &ClientJsonResource,
    index: usize,
    provider: &RawClientFontProviderDefinition,
) -> ResourceReloadResult<()> {
    let Some(size_overrides) = provider.fields.get("size_overrides") else {
        return Ok(());
    };
    let Some(size_overrides) = size_overrides.as_array() else {
        return Err(invalid_font_definition(
            resource,
            format!("provider {index} unihex size_overrides must be an array"),
        ));
    };

    for (override_index, size_override) in size_overrides.iter().enumerate() {
        let Some(size_override) = size_override.as_object() else {
            return Err(invalid_font_definition(
                resource,
                format!(
                    "provider {index} unihex size_overrides {override_index} must be an object"
                ),
            ));
        };
        for field in ["from", "to", "left", "right"] {
            if !size_override
                .get(field)
                .is_some_and(serde_json::Value::is_i64)
            {
                return Err(invalid_font_definition(
                    resource,
                    format!(
                        "provider {index} unihex size_overrides {override_index} `{field}` must be an integer"
                    ),
                ));
            }
        }
        let from = size_override
            .get("from")
            .and_then(serde_json::Value::as_i64)
            .unwrap_or_default();
        let to = size_override
            .get("to")
            .and_then(serde_json::Value::as_i64)
            .unwrap_or_default();
        if from >= to {
            return Err(invalid_font_definition(
                resource,
                format!(
                    "provider {index} unihex size_overrides {override_index} range must have from below to"
                ),
            ));
        }
    }

    Ok(())
}

fn require_font_provider_identifier_field<'a>(
    resource: &ClientJsonResource,
    index: usize,
    provider: &'a RawClientFontProviderDefinition,
    field: &str,
) -> ResourceReloadResult<&'a str> {
    let value = provider
        .fields
        .get(field)
        .and_then(serde_json::Value::as_str)
        .ok_or_else(|| {
            invalid_font_definition(
                resource,
                format!("provider {index} `{field}` must be a string"),
            )
        })?;
    if !is_valid_vanilla_resource_identifier(value) {
        return Err(invalid_font_definition(
            resource,
            format!("provider {index} `{field}` must be a resource identifier"),
        ));
    }
    Ok(value)
}

fn require_font_provider_i64_field(
    resource: &ClientJsonResource,
    index: usize,
    provider: &RawClientFontProviderDefinition,
    field: &str,
) -> ResourceReloadResult<i64> {
    provider
        .fields
        .get(field)
        .and_then(serde_json::Value::as_i64)
        .ok_or_else(|| {
            invalid_font_definition(
                resource,
                format!("provider {index} `{field}` must be an integer"),
            )
        })
}

fn require_font_provider_object_field<'a>(
    resource: &ClientJsonResource,
    index: usize,
    provider: &'a RawClientFontProviderDefinition,
    field: &str,
) -> ResourceReloadResult<&'a serde_json::Map<String, serde_json::Value>> {
    provider
        .fields
        .get(field)
        .and_then(serde_json::Value::as_object)
        .ok_or_else(|| {
            invalid_font_definition(
                resource,
                format!("provider {index} `{field}` must be an object"),
            )
        })
}

fn invalid_font_definition(
    resource: &ClientJsonResource,
    reason: impl Into<String>,
) -> ResourceReloadError {
    ResourceReloadError::InvalidFontDefinition {
        resource: resource.report().resource().to_owned(),
        pack_id: resource.report().pack_id().to_owned(),
        reason: reason.into(),
    }
}

fn font_provider_referenced_assets(
    resource: &ClientJsonResource,
    index: usize,
    provider: &RawClientFontProviderDefinition,
) -> ResourceReloadResult<Vec<String>> {
    match provider.provider_type.as_str() {
        "reference" => {
            let id = require_font_provider_identifier_field(resource, index, provider, "id")?;
            Ok(vec![font_definition_resource_path_for_identifier(id)])
        }
        "bitmap" => {
            let file = require_font_provider_identifier_field(resource, index, provider, "file")?;
            Ok(vec![font_bitmap_resource_path_for_identifier(file)])
        }
        "ttf" => {
            let file = require_font_provider_identifier_field(resource, index, provider, "file")?;
            Ok(vec![font_file_resource_path_for_identifier(file)])
        }
        "unihex" => {
            let hex_file =
                require_font_provider_identifier_field(resource, index, provider, "hex_file")?;
            Ok(vec![resource_path_for_identifier(hex_file)])
        }
        "space" => Ok(Vec::new()),
        _ => Ok(Vec::new()),
    }
}

fn font_provider_asset_candidates(
    resource: &ClientJsonResource,
    index: usize,
    provider: &RawClientFontProviderDefinition,
) -> ResourceReloadResult<Vec<ClientFontProviderAssetCandidate>> {
    let candidate = match provider.provider_type.as_str() {
        "bitmap" => {
            let file = require_font_provider_identifier_field(resource, index, provider, "file")?;
            Some(ClientFontProviderAssetCandidate {
                kind: ClientFontProviderAssetKind::BitmapTexture,
                resource: font_bitmap_resource_path_for_identifier(file),
            })
        }
        "ttf" => {
            let file = require_font_provider_identifier_field(resource, index, provider, "file")?;
            Some(ClientFontProviderAssetCandidate {
                kind: ClientFontProviderAssetKind::TrueTypeFont,
                resource: font_file_resource_path_for_identifier(file),
            })
        }
        "unihex" => {
            let hex_file =
                require_font_provider_identifier_field(resource, index, provider, "hex_file")?;
            Some(ClientFontProviderAssetCandidate {
                kind: ClientFontProviderAssetKind::UnihexFile,
                resource: font_file_resource_path_for_identifier(hex_file),
            })
        }
        _ => None,
    };
    Ok(candidate.into_iter().collect())
}

fn font_provider_referenced_provider_ids(
    resource: &ClientJsonResource,
    index: usize,
    provider: &RawClientFontProviderDefinition,
) -> ResourceReloadResult<Vec<String>> {
    if provider.provider_type != "reference" {
        return Ok(Vec::new());
    }
    let id = require_font_provider_identifier_field(resource, index, provider, "id")?;
    Ok(vec![id.to_owned()])
}

fn font_provider_glyph_source_estimate(
    resource: &ClientJsonResource,
    index: usize,
    provider: &RawClientFontProviderDefinition,
) -> ResourceReloadResult<Option<ClientFontGlyphSourceEstimate>> {
    match provider.provider_type.as_str() {
        "bitmap" => {
            let chars = provider
                .fields
                .get("chars")
                .and_then(serde_json::Value::as_array)
                .ok_or_else(|| {
                    invalid_font_definition(
                        resource,
                        format!("provider {index} bitmap chars must be an array"),
                    )
                })?;
            let count = chars
                .iter()
                .filter_map(serde_json::Value::as_str)
                .flat_map(str::chars)
                .filter(|codepoint| *codepoint != '\0')
                .count();
            Ok(Some(ClientFontGlyphSourceEstimate::BitmapChars(count)))
        }
        "space" => {
            let advances =
                require_font_provider_object_field(resource, index, provider, "advances")?;
            Ok(Some(ClientFontGlyphSourceEstimate::SpaceAdvances(
                advances.len(),
            )))
        }
        "ttf" => Ok(Some(ClientFontGlyphSourceEstimate::TrueTypePresent)),
        "unihex" => {
            let count = provider
                .fields
                .get("size_overrides")
                .and_then(serde_json::Value::as_array)
                .map_or(0, Vec::len);
            Ok(Some(ClientFontGlyphSourceEstimate::UnihexSizeOverrides(
                count,
            )))
        }
        "reference" => Ok(None),
        _ => Ok(None),
    }
}

fn font_definition_resource_path_for_identifier(identifier: &str) -> String {
    let (namespace, path) = resource_identifier_parts(identifier);
    format!("assets/{namespace}/font/{path}.json")
}

fn font_bitmap_resource_path_for_identifier(identifier: &str) -> String {
    resource_path_for_identifier_with_prefix(identifier, "textures")
}

fn font_file_resource_path_for_identifier(identifier: &str) -> String {
    resource_path_for_identifier_with_prefix(identifier, "font")
}

fn resource_path_for_identifier_with_prefix(identifier: &str, prefix: &str) -> String {
    let (namespace, path) = resource_identifier_parts(identifier);
    let path = path.strip_prefix(&format!("{prefix}/")).unwrap_or(path);
    format!("assets/{namespace}/{prefix}/{path}")
}

fn resource_path_for_identifier(identifier: &str) -> String {
    let (namespace, path) = resource_identifier_parts(identifier);
    format!("assets/{namespace}/{path}")
}

fn font_definition_report_item(report: ClientFontDefinitionReloadReport<'_>) -> String {
    let provider_types = report.provider_types().collect::<Vec<_>>().join(",");
    let mut item = format!(
        "{}:providers:{}:types:{}",
        report.resource().loaded_resource_pack(),
        report.provider_count(),
        provider_types
    );
    let referenced_assets = report.referenced_assets().collect::<Vec<_>>();
    if !referenced_assets.is_empty() {
        item.push_str(":refs:");
        item.push_str(&referenced_assets.join(","));
    }
    item
}

