    #[test]
    fn gpu_warnlist_reload_applies_pack_priority_overrides() {
        let base = TempPack::new();
        let override_pack = TempPack::new();
        base.write(
            GPU_WARNLIST_RESOURCE,
            r#"{"renderer":["base"],"version":[],"vendor":[]}"#,
        );
        base.write(REGIONAL_COMPLIANCIES_RESOURCE, r#"{"BASE":[]}"#);
        override_pack.write(
            GPU_WARNLIST_RESOURCE,
            r#"{"renderer":[],"vendor":["override"],"version":[]}"#,
        );
        override_pack.write(REGIONAL_COMPLIANCIES_RESOURCE, r#"{"OVERRIDE":[]}"#);

        let stack = ClientResourceStack::new(vec![
            ClientResourcePack::new("base", base.path()),
            ClientResourcePack::new("override", override_pack.path()),
        ]);

        let gpu_warnlist = GpuWarnlistReloadListener::default()
            .load(&stack)
            .expect("gpu warnlist should load from highest priority pack");
        let compliancies = RegionalComplianciesReloadListener::default()
            .load(&stack)
            .expect("regional compliancies should load from highest priority pack");

        assert_eq!(gpu_warnlist.report().resource(), GPU_WARNLIST_RESOURCE);
        assert_eq!(gpu_warnlist.report().pack_id(), "override");
        assert_eq!(gpu_warnlist.report().renderer_pattern_count(), 0);
        assert_eq!(gpu_warnlist.report().version_pattern_count(), 0);
        assert_eq!(gpu_warnlist.report().vendor_pattern_count(), 1);
        assert_eq!(
            gpu_warnlist.evaluate(&GpuWarnlistDeviceInfo::new(
                "OpenGL",
                "base renderer",
                "4.6",
                "override vendor"
            )),
            GpuWarnlistWarnings {
                renderer: Vec::new(),
                version: Vec::new(),
                vendor: vec!["override".to_owned()],
            }
        );
        assert_eq!(compliancies.report().pack_id(), "override");
        assert_eq!(
            compliancies.report().resource(),
            REGIONAL_COMPLIANCIES_RESOURCE
        );
        assert_eq!(
            compliancies.report().status(),
            RegionalComplianciesReloadStatus::Loaded
        );
        assert_eq!(compliancies.report().country_count(), 1);
        assert_eq!(compliancies.report().notification_count(), 0);
        assert_eq!(compliancies.report().zero_period_count(), 0);
        assert_eq!(
            compliancies.report().country_keys(),
            ["OVERRIDE".to_owned()]
        );
    }

